        private List<CermatTask> GetMaturita2024Podzim()
        {
            string textSportovkyne = @"<div class='columns-1 lg:columns-2 gap-8 space-y-4 text-slate-800 dark:text-slate-300 text-sm md:text-base text-justify'>
                <p>Když v anketě Sportovec roku 2023 vyhrála tenistka Markéta Vondroušová, nebylo divu – poslední dobou jsou totiž u nás v individuálních sportech úspěšnější ženy. Získávají víc medailí než muži a hvězdné výkony Ester Ledecké nebo Martiny Sáblíkové <b>přitáhly</b> k ženskému sportu spoustu fanoušků. Jeho popularita ostatně strmě roste i ve světě. K tomuto vzestupu ale vedla stovky let trvající cesta. Pro ženský sport bylo nutné především získat veřejnost, značně <b>[ ***** ]</b> předsudky. Například že ženské tělo je pro sport křehké nebo že sportování způsobí ženám neplodnost. Ještě na počátku 20. století tvrdil zakladatel moderního olympismu Pierre de Coubertin, že jedinou úlohou žen ve sportu je zdobit vavřínovou snítkou hlavy mužských vítězů.</p>
                <p>K vyvrácení takových mýtů přispěla i Alfonsina Strada. Letos je tomu 100 let, co se jako jediná žena v historii zúčastnila Giro d'Italia. Na tomto cyklistickém závodě smějí tradičně startovat jen muži, proto se Strada přihlásila pod mužským jménem Alfonsin. Pořadatelé její identitu sice odhalili, nakonec jí však <b>povolili</b> na trasu dlouhou 3 613 km <b>vyrazit</b>. V prvním týdnu konkurovala Strada soupeřům, a to i v etapách <b>[ ..... ]</b> horskými průsmyky. Pak ale přišel nečekaný zvrat. Osmý den se přihnala sněhová vánice, v níž cyklistka několikrát havarovala. Při jednom pádu dokonce zlomila řídítka. Na jejich místo ale zastrčila násadu od koštěte a etapu dokončila. A poté i celý závod – 12. ročník Gira přitom zvládlo kromě ní jen 30 závodníků z původních 90. Po dojezdu do Milána oslavovaly „Ďábla v sukni“ (tak se Alfonsině přezdívalo) davy fanoušků.</p>
                <p>DÍKY odvaze Alfonsiny Strady a dalších sportovkyň (například Kathrine Switzer, která byla napadena, když roku 1967 běžela Bostonský maraton) se přístup k ženskému sportu začal měnit. Do dějin se zapsala olympiáda roku 2012 v Londýně, na niž poprvé každý z účastnických států vyslal soutěžit alespoň jednu ženskou reprezentantku. Pokud bude příznivý trend pokračovat, sportovkyně se snad dočkají i lepšího ohodnocení své práce.</p>
                <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium'>(inspirováno články v časopisech Respekt a 100+1 zahraniční zajímavost)</p>
            </div>";

            string textSvatopluk = @"<div class='grid grid-cols-1 lg:grid-cols-2 gap-8 text-slate-800 dark:text-slate-300 text-sm md:text-base'>
                <div>
                    <h4 class='text-[10px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-4'>TEXT 1</h4>
                    <p class='whitespace-pre-line italic mb-4'><b>(1)</b>
                    Otrokem jsem zplozen,
                    otrokyní zrozen,
                    kolébavkou býval
                    děcku pouta chřest,
                    <b>po</b> můj život celý
                    okov zrezavělý
                    ve dne v noci zníval
                    pustinou mých cest.</p>
                    <p class='whitespace-pre-line italic mb-4'><b>(2)</b>
                    A přec oko časem
                    plachým svitlo jasem,
                    napínal jsem ucho
                    za les, za vody;
                    mnil jsem, že tam kdesi
                    jásá pod nebesy,
                    letí v naše hlucho
                    píseň svobody.</p>
                </div>
                <div>
                    <p class='whitespace-pre-line italic mb-4'><b>(3)</b>
                    Rost jsem, otrok chabý,
                    mezi bratry raby,
                    za šperk okov zvonil
                    sestrám u boků,
                    a kam zřel jsem kolem
                    s hanbou, hněvem, bolem,
                    do prachu leb klonil
                    národ otroků.</p>
                    <p class='whitespace-pre-line italic mb-4'><b>(4)</b>
                    Již se vaz můj chýlí,
                    na skráni vlas bílý,
                    naděje už v temnou
                    jeseň nekynou,
                    že mé ruce spjaté
                    setřesou jho klaté –
                    vím, že pouta se mnou
                    v hrobě spočinou.</p>
                    <p class='whitespace-pre-line italic mb-4'>Ale jak se vznesla,
                    hlava zase klesla,
                    znova v hanbě, hoři
                    rok šel za rokem…
                    V šíji dosud jarmo
                    a zrak čeká darmo
                    vykoupení v zoři –
                    zemru otrokem!</p>
                    <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium mb-6'>Vysvětlivky: rab – otrok; jarmo, jho – útlak; mnít – domnívat se; jeseň – podzim<br>(Svatopluk Čech, Písně otroka, upraveno)</p>
                    
                    <h4 class='text-[10px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-4'>TEXT 2</h4>
                    <p>Rýmují-li se v básni dva verše končící různými slovy, z nichž jedno slovo je celé obsaženo v tom druhém, vzniká <b>rýmové echo</b>, např. <i>a na topole podle skal / zelený mužík zatleskal</i>.</p>
                </div>
            </div>";

            string textRimbaud = @"<div class='space-y-4 text-slate-800 dark:text-slate-300 text-sm md:text-base text-justify'>
                <p><b>(1)</b> Po roce 1848 procházela francouzská literatura proměnou. Témata a výrazové prostředky romantismu (zejména vznícená citovost a revoluční angažovanost) se již přežily a vůdčím uměleckým směrem se stal <b>[ ***** ]</b>, typický svými romány založenými na zdánlivě objektivním pozorování skutečnosti. Na jednom z nejslavnějších, Paní Bovaryové, tehdy pracoval <b>[ ..... ]</b>. Poezie stála na rozcestí – vyšla dokonce stať pojednávající o tom, proč o <b>ni</b> francouzské publikum už ztratilo zájem. To podnítilo <b>některé literáty</b>, aby hledali nové podoby básnického výrazu. <b>Jejich</b> snahy vyvrcholily v roce 1866 vydáním sborníku Současný Parnas – tvůrcům sdruženým kolem něj se začalo říkat parnasisté. Parnasistická poezie vynikala silnou smyslovostí a vybroušenou formou.</p>
                <p>V září roku 1871, když se pracovalo na druhém svazku Současného Parnasu, přivedl Paul Verlaine na společnou večeři parnasistů Jeana Arthura Rimbauda, s nímž se nedávno seznámil. Nováček tu přečetl báseň Opilý koráb a další své verše. Reakce spolustolovníků lze vyjádřit jen slovy obdiv a úžas. Večeře se nemohl zúčastnit spisovatel Émile Blémont, a tak se nám líčení oné události dochovalo v listu, který mu napsal přítel Léon Valade:</p>
                <p><b>(2)</b> „To jste přišel o mnoho. Pod patronátem Verlaina byl tu předveden strašlivý básník, není mu ještě osmnáct. Velké ruce, absolutně dětská tvář, jaká se hodí tak k třináctiletému chlapci, povaha spíš divoká než bojácná, tak vypadá ten kluk. Z jeho životopisu Vám teď mnoho nepovím. Vězte ale, že je rozhodnut nikdy se nevrátit do rodného kraje. Přijďte a uvidíte sám. Je to vzcházející génius.“</p>
                <p><b>(3)</b> Zájem o <u>dílo, které rozvířilo stojaté vody poezie</u>, ale záhy opadl. Zanedlouho byl <u>mladík, o němž se s nadšením psalo v dopise</u>, pokládán za vyšinutého <u>člověka, jenž zavádí poezii na nebezpečné cesty</u>. Ti nejshovívavější v něm viděli hvězdu, jež zazáří jen krátce, <u>talent, který vmžiku shoří a navždy zapadne do nicoty</u>. Rimbaudovu hodnotu musely objevit až další generace – pro mnoho moderních umělců se stal nedostižným vzorem.</p>
                <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium'>(Vzhledem k povaze jedné z úloh není zdroj výchozího textu uveden.)</p>
            </div>";

            string textRvacu = @"<div class='grid grid-cols-1 lg:grid-cols-2 gap-8 text-slate-800 dark:text-slate-300 text-sm md:text-base'>
                <div>
                    <h4 class='text-[10px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-4'>TEXT 1</h4>
                    <p class='mb-4 text-justify'><b>(1)</b> Tyler a já jsme se stali sabotéry hostin. K hostině totiž klienti dostanou i personál: jídlo a služby na jednom účtu. Na takových akcích se spropitné nedává, jsi pro ně jen šváb. Kdysi Tyler pracoval jako číšník na hostině ve vile podobné prosklenému obláčku, jenž se vznáší nad městem. Právě byl naservírován rybí chod a Tyler oplachuje talíře od prvního, těstovinového chodu. Do kuchyně vchází hostitelka a mává kusem papíru. Ten povlává jako <b>vlajka</b>, tak moc se jí třese ruka. Madam PROCEDÍ skrz zaťaté zuby, zda číšníci neviděli někoho z hostů proklouznout nenápadně <u>chodbou</u> k ložnici. Zvlášť některou z <b>dam</b>.</p>
                    <p class='mb-4 text-justify'>Tyler k ní vzhlédne, ostatní číšníci dál myjí nádobí. Pomocný kuchař Leslie se věnuje chodu, který je podle menu na řadě: podlévá plněné artyčoky <b>máslem</b>. Když se nikdo z tázaných nemá k odpovědi, řekne Tyler:</p>
                    <p class='mb-4 text-justify'><b>(2)</b> „Do té části domu nesmíme. Přijdeme garáží a máme vidět jen kuchyň a jídelnu.“ Vtom vstoupí hostitel a vezme ženě z ruky ten <b>cár</b> papíru. „To bude v pořádku,“ říká.</p>
                </div>
                <div>
                    <p class='mb-4 text-justify'>„Jak můžu jít mezi ty lidi,“ vyhrkne madam, celá rozrušená, „když nevím, kdo to udělal?“ Hostitel jí položí dlaň na záda bílých šatů, barevně sladěných s domem, a žena se narovná – jednoduché gesto způsobí, že je najednou klidná.</p>
                    <p class='mb-4 text-justify'><b>(3)</b> „Jsou to naši hosti,“ říká hostitel, „a tenhle večírek je důležitý.“ Pak už mu stačí manželku jen trochu postrčit, načež odejdou zpátky do jídelny. Když procházejí létacími dveřmi, závan vzduchu dožene Tylerovi k nohám vzkaz, odhozený na podlahu.</p>
                    <p class='mb-4'>„Co se tam píše?“ ptá se Albert, jeden z číšníků. Tyler ani nezvedne papír a odpoví:<br>„<u>Vpravila jsem <b>něco</b> moči nejméně do jednoho z vašich četných parfémů.</u>“<br>Albert se usmívá: „Tys jí dal moč do voňavky?“<br>„Jen jsem nechal ten lístek mezi lahvičkami v koupelně – má jich tam asi sto,“ říká Tyler.<br>„Takže vlastně nedal?“<br>„Ne, ale to ona neví.“</p>
                    <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium mb-6'>(Ch. Palahniuk, Klub rváčů, upraveno)</p>
                    
                    <h4 class='text-[10px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-4'>TEXT 2</h4>
                    <p class='mb-2 text-justify'>Podstatné jméno typu <b>A</b> (např. <i>duše</i>) – ve všech tvarech tohoto podstatného jména má kořen stejnou podobu.</p>
                    <p class='text-justify'>Podstatné jméno typu <b>B</b> (např. <i>práce</i>) – v některých tvarech tohoto podstatného jména obsahuje kořen dlouhou samohlásku (práci) a v některých krátkou (pracemi).</p>
                </div>
            </div>";

            string textKvetinace = @"<div class='bg-slate-100 dark:bg-slate-900/50 p-5 rounded-2xl border border-slate-200 dark:border-white/5 space-y-4 text-slate-800 dark:text-slate-300 text-sm md:text-base text-justify'>
                <p>Není mnoho výrobků českého původu, které by si získaly oblibu v zahraničí. Určitě k nim ale patří samozavlažovací nádoby na rostliny. Toto zařízení vynalezl lékař Tomáš Syrovátka, patentováno bylo v dubnu 1982 a první samozavlažovací květináč byl vyroben v roce 1984 v obci Vyskeř. O působivé novince z Československa pak informovaly časopisy nejen v evropských zemích, ale také v USA či Indii a květináče se brzy rozšířily do celého světa.</p>
                <p>A v čem spočívá princip těchto květináčů? Jedná se o dvě <u>vzájemě</u> propojené plastové nádoby: do té <b>spodní</b>, v níž jsou zásoby vody, je vložena druhá nádoba se zeminou a rostlinami. Vláha do půdy průběžně vzlíná pomocí knotů. Zajištěno je i provzdušnění, a to pomocí horizontální vzduchové mezery pod vrstvou zeminy. Vodní režim samozavlažovacích nádob se podobá volné přírodě tím, že půda udržuje <b>trvalé</b> množství vlhkosti.</p>
                <p>Samozavlažovací truhlíky umožnily pěstovat na terasách, okenních římsách i uvnitř bytů náročnější bylinné druhy, či dokonce ovocné stromy. Střídání přemokření a <u>vysichání</u> hlíny totiž řadě rostlin nesvědčí, proto většinou v <b>běžných</b> truhlících <u>neprozpívají</u>. Dostatečná vlhkost je i spolehlivou <u>ochrannou</u> proti <b>prudkému</b> slunci. Aby vás ale název „samozavlažovací“ nespletl – vodu musíte doplnit jen jednou za několik týdnů, nicméně nádoba si ji sama neobstará. Kdo však ví, kam nás jednou pokrok zavede...</p>
                <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium'>Vysvětlivka: knot – pruh textilie, který ponořeným koncem nasaje kapalinu a umožní tak její pohyb vzhůru<br>(Biblio 6/2009; www.bydleni.cz, upraveno)</p>
            </div>";

