                new CermatTask { TaskNumber = "9", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení odpovídá TEXTU 1 (básni Svatopluka Čecha)?", TextBase = textSvatopluk, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "Lyrický subjekt v určité fázi svého života už nedoufal, že by se někdy mohl stát svobodným." }, new TaskOption { Label = "B", Text = "Lyrický subjekt nemohl v dětství často usnout, protože byl přikován ke kolébce chřestícími pouty." }, new TaskOption { Label = "C", Text = "Lyrický subjekt navrhuje, že obětuje svůj zrak, pokud bude výměnou za tuto oběť vykoupen z otroctví." }, new TaskOption { Label = "D", Text = "Lyrický subjekt sděluje, že jeho sestrám byly odcizeny šperky a na boky jim byly místo ozdob připevněny okovy." } }, Explanation = "Čtvrtá sloka říká: 'naděje už v temnou jeseň nekynou... vím, že pouta se mnou v hrobě spočinou' – tedy nedoufal, že se stane svobodným." },
                new CermatTask { TaskNumber = "10", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o druhé a třetí části TEXTU 1 je pravdivé? (Základ: rýmové echo = slovo z rýmu je celé obsaženo v druhém, např. skal / zatleskal).", TextBase = textSvatopluk, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "Rýmové echo se vyskytuje jak v druhé, tak ve třetí části textu." }, new TaskOption { Label = "B", Text = "Rýmové echo se nevyskytuje ani v druhé, ani ve třetí části textu." }, new TaskOption { Label = "C", Text = "Rýmové echo se vyskytuje v druhé, nikoli však ve třetí části textu." }, new TaskOption { Label = "D", Text = "Rýmové echo se vyskytuje ve třetí, nikoli však v druhé části textu." } }, Explanation = "Ve druhé části: ucho – hlucho ('ucho' je součástí 'hlucho'). Ve třetí části: rokem – otrokem ('rokem' je součástí 'otrokem')." },
                new CermatTask { TaskNumber = "11", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Medailonek: Svatopluk Čech patřil k ruchovcům (skupině umělců, která kladla důraz na národní uvědomění v literatuře), tvořil převážně v 2. polovině 19. století a kromě poezie psal i prózy, např. Pravý výlet pana Broučka do Měsíce. Jsou všechny informace pravdivé?", ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "Ano, všechny tyto informace jsou pravdivé." }, new TaskOption { Label = "B", Text = "Ne – aby byly pravdivé, je nutné slovo ruchovci nahradit slovem májovci." }, new TaskOption { Label = "C", Text = "Ne – aby byly pravdivé, je nutné časový údaj 19. století nahradit údajem 20. století." }, new TaskOption { Label = "D", Text = "Ne – aby byly pravdivé, je nutné název díla Pravý výlet... nahradit názvem Noc na Karlštejně." } }, Explanation = "Všechna zmíněná fakta o Svatopluku Čechovi se zakládají na pravdě." },
                new CermatTask { TaskNumber = "12", Category = TaskCategory.Ordering, MaxPoints = 3, Instruction = "Seřaďte jednotlivé části textu (A–E) tak, aby byla dodržena textová návaznost (Zima v horách).", ExpectedSequence = new() { "B", "A", "E", "C", "D" }, Options = new() { new TaskOption { Label = "A", Text = "Stačily dva nebo tři údery ostrou hranou kamene a namísto skleněné tabulky zel prázdný prostor, do kterého vnořil paži. Uvolnil západku a okno se otevřelo dokořán. Vtom uslyšel Rhiannoniny kroky – blížila se zezadu kolem kaple." }, new TaskOption { Label = "B", Text = "Když si okno prohlédl, zmocnila se ho rozhodnost: měl by jednat raději hned, aby si to zas nerozmyslel. Seskočil dolů, hledal vhodný kámen, našel ho a znovu se vyšplhal na úzkou římsu pod oknem." }, new TaskOption { Label = "C", Text = "Vteřinku počkal, aby nabral dech, ještě jednou se vzepřel, odrazil se a už ležel na prkenné podlaze kaple uprostřed prachu a skleněných střepů." }, new TaskOption { Label = "D", Text = "Rychle vstal, oprášil si dlaně – neřízl se, dokonce si nezpůsobil ani žádné vážnější odřeniny – a pak sebevědomě vykročil směrem k hlavním dveřím." }, new TaskOption { Label = "E", Text = "Nepřál si, aby ho spatřila, jak nedůstojně zápasí s nohama komíhajícíma se ve vzduchu, a proto bez váhání vsoukal hlavu a ramena do otevřeného prostoru. Protáhl se skrz a zastavil se s rukama na vnitřním parapetu okna a s koleny bolestně zarytými do kovového rámu." } }, Explanation = "Prohlédl okno a vzal kámen (B) -> Rozbil okno a otevřel ho, blížily se kroky (A) -> Rychle vsoukal ramena, aby nebyl vidět z venku (E) -> Odrazil se a dopadl na podlahu (C) -> Vstal a vykročil ke dveřím (D)." },
                new CermatTask { TaskNumber = "13", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících vět NENÍ zapsána pravopisně správně?", ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Z médií se na mě snesla vlna kritiky." }, new TaskOption { Label = "B", Text = "Všechny povinnosti tu teď leží na mně." }, new TaskOption { Label = "C", Text = "O mě se v tom shonu nikdo moc nestaral." }, new TaskOption { Label = "D", Text = "Oba sousedovi synové se o mně tehdy ucházeli." } }, Explanation = "Ucházet se 'o koho, co' = 4. pád (na mě / tebe), takže má být sneslo se na 'mě'." },
                new CermatTask { TaskNumber = "14", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve kterém z úseků podtržených ve výchozím textu o Rimbaudovi se NEUPLATŇUJE obraznost?", TextBase = textRimbaud, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "dílo, které rozvířilo stojaté vody poezie" }, new TaskOption { Label = "B", Text = "mladík, o němž se s nadšením psalo v dopise" }, new TaskOption { Label = "C", Text = "člověka, jenž zavádí poezii na nebezpečné cesty" }, new TaskOption { Label = "D", Text = "talent, který vmžiku shoří a navždy zapadne do nicoty" } }, Explanation = "Úsek B je jediný zcela doslovný (přímé pojmenování faktu), zbylé využívají metafory (rozvířit stojaté vody, zavádět na nebezpečné cesty, talent shoří)." },
                new CermatTask { TaskNumber = "15", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Na vynechaná místa [ ***** ] a [ ..... ] ve výchozím textu patří správný název uměleckého směru a autor románu Paní Bovaryová. Která je to možnost?", TextBase = textRimbaud, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "realismus – Gustave Flaubert" }, new TaskOption { Label = "B", Text = "realismus – Alexandre Dumas" }, new TaskOption { Label = "C", Text = "klasicismus – Gustave Flaubert" }, new TaskOption { Label = "D", Text = "klasicismus – Alexandre Dumas" } }, Explanation = "Směr 2. poloviny 19. stol. zdůrazňující objektivitu je realismus. Autorem Paní Bovaryové je Gustave Flaubert." },
                new CermatTask { TaskNumber = "16", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících tvrzení, zda jednoznačně vyplývá z výchozího textu (Rimbaud).", TextBase = textRimbaud, Items = new() { new SubItem { Id = "16.1", Text = "Úspěch Paní Bovaryové a dalších románů způsobil, že se roku 1848 francouzská literatura proměnila.", ExpectedAnswer = "NE" }, new SubItem { Id = "16.2", Text = "Každý z parnasistů, kteří si na večeři v září 1871 vyslechli báseň Opilý koráb, řekl Jeanu Arthuru Rimbaudovi osobně, jak toto jeho dílo obdivuje.", ExpectedAnswer = "NE" }, new SubItem { Id = "16.3", Text = "Opilý koráb a další básně Jeana Arthura Rimbauda se dochovaly pouze v listu, jehož součástí bylo vylíčení večeře parnasistů ze září roku 1871.", ExpectedAnswer = "NE" }, new SubItem { Id = "16.4", Text = "Zatímco o vydání prvního svazku Současného Parnasu se básníci snažili od roku 1848 až do roku 1866, práce na jeho druhém svazku trvala jen pět let.", ExpectedAnswer = "NE" } }, Explanation = "16.1 Ne (proměna začala po roce 1848). 16.2 Ne (text jen říká, že reakce lze vyjádřit jako úžas, ne že mu to osobně říkali). 16.3 Ne (v listu se dochovalo líčení události, ne samotné básně). 16.4 Ne (o snahách vydávat 18 let text nemluví)." },
                new CermatTask { TaskNumber = "17", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o zájmenech 'ni' a 'jejich', tučně vyznačených v první části výchozího textu, je pravdivé?", TextBase = textRimbaud, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "První zájmeno odkazuje ke slovu stať, druhé ke slovnímu spojení nové podoby." }, new TaskOption { Label = "B", Text = "První zájmeno odkazuje ke slovu stať, druhé ke slovnímu spojení někteří literáti." }, new TaskOption { Label = "C", Text = "První zájmeno odkazuje ke slovu poezie, druhé ke slovnímu spojení nové podoby." }, new TaskOption { Label = "D", Text = "První zájmeno odkazuje ke slovu poezie, druhé ke slovnímu spojení někteří literáti." } }, Explanation = "'proč o ni (poezii) publikum ztratilo zájem... podnítilo literáty... jejich (literátů) snahy'." },
                new CermatTask { TaskNumber = "18", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení nejlépe vystihuje druhou část výchozího textu ('To jste přišel o mnoho...')?", TextBase = textRimbaud, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Jde o pasáž z textu adresovaného Léonu Valadovi, která obsahuje stručnou biografii Jeana Arthura Rimbauda." }, new TaskOption { Label = "B", Text = "Jde o pasáž z textu adresovaného Émilu Blémontovi, která obsahuje stručnou biografii Jeana Arthura Rimbauda." }, new TaskOption { Label = "C", Text = "Jde o pasáž z textu adresovaného Léonu Valadovi, která obsahuje stručnou charakteristiku Jeana Arthura Rimbauda." }, new TaskOption { Label = "D", Text = "Jde o pasáž z textu adresovaného Émilu Blémontovi, která obsahuje stručnou charakteristiku Jeana Arthura Rimbauda." } }, Explanation = "List napsal Valade příteli Blémontovi (adresát) a popisuje v něm fyzický a povahový zjev mladíka (charakteristika, nikoli životopisná biografie)." },
                new CermatTask { TaskNumber = "19", Category = TaskCategory.Correction, MaxPoints = 3, Instruction = "Vypište ze seznamu 3 NÁZVY PROSTŘEDKŮ (odvozeny od sloves, slouží jako nástroj). Seznam: rtěnka, horečka, hloubka, škrabka, trávník, vrtulník, budík, holubník, sušák, palčák, slamák, severák.", InputFieldsCount = 3, UserInputs = new string[] { "", "", "" }, ExpectedSequence = new() { "sušák", "budík", "škrabka" }, Explanation = "Nástroje k činnosti (od sloves): sušák (sušit), budík (budit), škrabka (škrábat)." },
                new CermatTask { TaskNumber = "20", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících tvrzení, zda jednoznačně vyplývá z TEXTU 1 (Klub rváčů).", TextBase = textRvacu, Items = new() { new SubItem { Id = "20.1", Text = "Lístek se vzkazem, jehož znění Tyler znal, odhodila na podlahu hostitelka.", ExpectedAnswer = "NE" }, new SubItem { Id = "20.2", Text = "Při hostině vnikla jedna z dam do hostitelčiny ložnice, což vyvolalo rozruch.", ExpectedAnswer = "NE" }, new SubItem { Id = "20.3", Text = "Rybí chod se na hostině podával později než těstovinový, ale dříve, než byly na řadě plněné artyčoky.", ExpectedAnswer = "ANO" }, new SubItem { Id = "20.4", Text = "Tyler se rozhodl neříct hostitelce pravdu o jejích parfémech, protože mu tato dáma odmítla dát očekávané spropitné.", ExpectedAnswer = "NE" } }, Explanation = "20.1 Ne (byl to cár papíru hostitelky, ale nevíme s jistotou, že ten lístek se vzkazem upustila zrovna ona). 20.2 Ne (hostitelka se jen bála, že tam někdo proklouzl, ne že tam vnikl skutečně). 20.3 Ano (Tyler myl po 1. těstovinovém, zrovna se nesl 2. rybí, a kuchař připravoval další: artyčoky). 20.4 Ne (dělal to z principu anarchie 'jsi pro ně jen šváb', nikoli proto, že mu odmítla dát spropitné, spropitné se celkově vůbec nedává)." },
                new CermatTask { TaskNumber = "21", Category = TaskCategory.Correction, MaxPoints = 2, Instruction = "Vypište z DRUHÉ (potažmo třetí) části TEXTU 1 dvě podstatná jména, která jsou užita ve stejném pádě a čísle jako slovo 'talíře' v úseku 'Tyler oplachuje talíře'.", TextBase = textRvacu, InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedSequence = new() { "lidi", "záda" }, Explanation = "Oplachuje talíře = 4. pád (koho co oplachuje), množné číslo. Ve druhé/třetí části: 'jít mezi ty lidi' (4. p. mn. č.) a 'položí dlaň na záda' (4. p. mn. č.)." },
                new CermatTask { TaskNumber = "22", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících slov je tvarem podstatného jména typu B (tj. v některých tvarech má kořen dlouhou, v některých krátkou samohlásku)?", TextBase = textRvacu, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "vlajka" }, new TaskOption { Label = "B", Text = "dam" }, new TaskOption { Label = "C", Text = "máslem" }, new TaskOption { Label = "D", Text = "cár" } }, Explanation = "Dáma má ve 2. pádě množného čísla krátkou samohlásku (těch dam). Střídá se tedy dáma/dam." },
                new CermatTask { TaskNumber = "23", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Těsně předtím, než hostitel vstoupil do kuchyně, se v ní nacházel Tyler a *****. Kterou možnost je nutné doplnit, aby tvrzení odpovídalo TEXTU 1?", TextBase = textRvacu, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "celkem dvě další postavy, z nichž jedna pracovala na hostině jako číšník" }, new TaskOption { Label = "B", Text = "celkem tři další postavy, z nichž nejméně dvě pracovaly na hostině jako číšníci" }, new TaskOption { Label = "C", Text = "alespoň tři další postavy, přičemž pouze jedna postava pracovala na hostině jako číšník" }, new TaskOption { Label = "D", Text = "alespoň čtyři další postavy, přičemž nejméně dvě postavy pracovaly na hostině jako číšníci" } }, Explanation = "Byl tam Tyler, hostitelka (1), kuchař Leslie (2) a 'ostatní číšníci' (tedy alespoň dva další číšníci - 3, 4). Takže tam byly aspoň čtyři další postavy." },
                new CermatTask { TaskNumber = "24", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z tvrzení o větném členu 'chodbou' podtrženém v TEXTU 1 je pravdivé?", TextBase = textRvacu, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Tímto větným členem je v příslušné větě rozvit větný člen z hostů." }, new TaskOption { Label = "B", Text = "Tímto větným členem je v příslušné větě rozvit větný člen proklouznout." }, new TaskOption { Label = "C", Text = "Tímto větným členem je v příslušné větě rozvit větný člen nenápadně." }, new TaskOption { Label = "D", Text = "Tímto větným členem je v příslušné větě rozvit větný člen k ložnici." } }, Explanation = "Slovo chodbou odpovídá na otázku 'kudy proklouznout?' Rozvíjí sloveso proklouznout." },
                new CermatTask { TaskNumber = "25", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve které z možností je význam slova 'něco' nejpodobnější významu, jejž má ve větě 'Vpravila jsem něco moči...'?", TextBase = textRvacu, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Šla si koupit něco k jídlu." }, new TaskOption { Label = "B", Text = "Z toho chlapce něco bude." }, new TaskOption { Label = "C", Text = "Zbylo mu aspoň něco peněz." }, new TaskOption { Label = "D", Text = "Dozvěděli se o ní něco hrozného." } }, Explanation = "Ve významu 'vpravila jsem trochu moči' je to synonymní se spojením 'něco peněz' = trochu peněz." },
                new CermatTask { TaskNumber = "26", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z tvrzení o slově PROCEDÍ (zapsaném velkými písmeny) je pravdivé?", TextBase = textRvacu, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Toto slovo není expresivní ani v daném kontextu, ani v souvětí Když táta vaří omáčku, procedí do ní šťávu." }, new TaskOption { Label = "B", Text = "Toto slovo je v daném kontextu expresivní, stejně jako v souvětí Když táta vaří omáčku, procedí do ní šťávu." }, new TaskOption { Label = "C", Text = "Toto slovo není v daném kontextu expresivní, v souvětí Když táta vaří omáčku, procedí do ní šťávu však expresivní je." }, new TaskOption { Label = "D", Text = "Toto slovo je v daném kontextu expresivní, v souvětí Když táta vaří omáčku, procedí do ní šťávu však expresivní není." } }, Explanation = "'Procedit skrz zuby' je v daném kontextu expresivní metafora pro zlostné vyřčení slov. Procedit omáčku je doslovné a neutrální." },
                new CermatTask { TaskNumber = "27", Category = TaskCategory.Correction, MaxPoints = 4, Instruction = "Najděte ve výchozím textu ČTYŘI slova zapsaná s pravopisnou chybou a napište je SPRÁVNĚ.", TextBase = textKvetinace, InputFieldsCount = 4, UserInputs = new string[] { "", "", "", "" }, ExpectedSequence = new() { "vzájemně", "vysychání", "neprospívají", "ochranou" }, Explanation = "vzájemě -> vzájemně; vysichání -> vysychání; neprozpívají -> neprospívají; ochrannou -> ochranou." },
                new CermatTask { TaskNumber = "28", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení jednoznačně vyplývá z výchozího textu o květináčích?", TextBase = textKvetinace, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Součástí vynálezu doktora Syrovátky jsou knoty, které jednou za několik týdnů nasají vodu do nádoby s rostlinami." }, new TaskOption { Label = "B", Text = "Samozavlažovací květináč je jedním z mála původních českých vynálezů rozšířených a oblíbených v zahraničí." }, new TaskOption { Label = "C", Text = "Dva roky po získání patentu se samozavlažovací květináče začaly vyvážet z obce Vyskeř do evropských i mimoevropských zemí." }, new TaskOption { Label = "D", Text = "Ve volné přírodě, podobně jako v samozavlažovacích nádobách, je vodní režim udržován horizontální vzduchovou mezerou pod vrstvou zeminy." } }, Explanation = "B: 'Není mnoho výrobků českého původu, které by si získaly oblibu v zahraničí. Určitě k nim ale patří...'" },
