            {
                new CermatTask { TaskNumber = "1", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících tvrzení, zda jednoznačně vyplývá z výchozího textu o Ig Nobelových cenách.", TextBase = textNobel, Items = new() { new SubItem { Id = "1.1", Text = "Poprvé se nějaký člověk stal držitelem Ig Nobelovy ceny v devadesátých letech minulého století.", ExpectedAnswer = "ANO" }, new SubItem { Id = "1.2", Text = "Andre Geim získal za stejný pokus jak Ig Nobelovu cenu, tak později i skutečnou Nobelovu cenu.", ExpectedAnswer = "NE" }, new SubItem { Id = "1.3", Text = "Pavlo Blavatský prokázal, že čím je v dané zemi vyšší míra korupce, tím rychleji tamější politici přibývají na váze.", ExpectedAnswer = "NE" }, new SubItem { Id = "1.4", Text = "Jedna z Ig Nobelových cen byla udělena za zjištění, že počet nudných učitelů je shodný s počtem nudících se žáků.", ExpectedAnswer = "NE" } }, Explanation = "1.1: Ano, poprvé uděleny roku 1991 (což jsou 90. léta). 1.2: Ne, získal je za různé věci (žáby v poli vs. grafen). 1.3: Ne, zjistil, že obezita politiků indikuje korupci, ne že kvůli korupci 'rychleji přibývají na váze'. 1.4: Ne, tým nezjišťoval shodu počtů, ale kdo se ve škole nudí víc (a jak se ovlivňují)." },
                new CermatTask { TaskNumber = "2", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení nejlépe vystihuje podtržené úseky výchozího textu?", TextBase = textNobel, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "V prvním úseku autor výchozího textu cituje z jiného než výchozího textu, totéž platí i pro druhý úsek." }, new TaskOption { Label = "B", Text = "V prvním úseku autor výchozího textu ironicky komentuje výrok redaktora satirického časopisu, totéž platí i pro druhý úsek." }, new TaskOption { Label = "C", Text = "V prvním úseku autor výchozího textu cituje z jiného než výchozího textu, v druhém úseku autor výchozího textu ironicky komentuje výrok redaktora satirického časopisu." }, new TaskOption { Label = "D", Text = "V prvním úseku autor výchozího textu ironicky komentuje výrok redaktora satirického časopisu, v druhém úseku autor výchozího textu cituje z jiného než výchozího textu." } }, Explanation = "Oba podtržené úseky jsou v uvozovkách, jedná se o doslovné citace z pravidel udělování Ig Nobelových cen. Autor neprovádí ironický komentář." },
                new CermatTask { TaskNumber = "3", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících slov je z hlediska významu užito ve výchozím textu CHYBNĚ?", TextBase = textNobel, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "autorita" }, new TaskOption { Label = "B", Text = "koncepce" }, new TaskOption { Label = "C", Text = "prezence" }, new TaskOption { Label = "D", Text = "rarita" } }, Explanation = "Slovo 'prezence' znamená přítomnost/účast. Ve větě mělo být správně použito slovo 'prezentace' (představení) výsledků." },
                new CermatTask { TaskNumber = "4", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Napište náležitý spisovný tvar slov 'hrdý' a 'věnovaný' tak, aby patřily na vynechaná místa v textu.", TextBase = "<b>[ 1 ]</b> laureáty se nejprve stávali ti... Během galavečera <b>[ 2 ]</b> této události...", InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"hrdými", "věnovaného"}, Explanation = "1. (kým, čím) hrdými laureáty (7. pád). 2. Během galavečera (koho, čeho) věnovaného (2. pád)." },
                new CermatTask { TaskNumber = "5", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o slovech BLÍZKÝ a ORIGINÁLNÍ, zapsaných ve výchozím textu velkými písmeny, je pravdivé?", TextBase = textNobel, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Jak blízký, tak originální jsou přívlastky rozvíjející slovo humor." }, new TaskOption { Label = "B", Text = "Jak blízký, tak originální jsou přívlastky rozvíjející slovo projekt." }, new TaskOption { Label = "C", Text = "Blízký je přívlastkem rozvíjejícím slovo humor, originální je součástí přísudku." }, new TaskOption { Label = "D", Text = "Blízký je přívlastkem rozvíjejícím slovo projekt, originální je součástí přísudku." } }, Explanation = "Spojení 'BLÍZKÝ svým pojetím' rozvíjí 'Projekt' (jaký projekt? blízký...), je to přívlastek volný. Slovo 'ORIGINÁLNÍ' je součástí jmenného přísudku se sponou ('je originální')." },
                new CermatTask { TaskNumber = "6", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Po které z úprav bude v textu s katakombami správně zapsána interpunkce?", TextBase = textKatakomby, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "doplní-li se čárka pouze na místo označené [1]" }, new TaskOption { Label = "B", Text = "doplní-li se čárka pouze na místo označené [2]" }, new TaskOption { Label = "C", Text = "doplní-li se dvě čárky, a to na místo označené [1] a na místo označené [2]" }, new TaskOption { Label = "D", Text = "doplní-li se dvě čárky, a to na místo označené [2] a na místo označené [3]" } }, Explanation = "Vložený přístavek 'často přezdívané Říše smrti' se musí z obou stran oddělit čárkou (místa 1 a 2)." },
                new CermatTask { TaskNumber = "7", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících souvětí, zda je zapsáno pravopisně SPRÁVNĚ.", Items = new() { new SubItem { Id = "7.1", Text = "Když se opět sklonil k mikroskopu, spatřil na sklíčku zvláštní zhluk buněk.", ExpectedAnswer = "NE" }, new SubItem { Id = "7.2", Text = "Četbu místních novin úplně vzdala, neboť v nich byly samé skličující zprávy.", ExpectedAnswer = "ANO" }, new SubItem { Id = "7.3", Text = "Komáři a mouchy létali kolem rozsvícené lampy, po setmění se v bytě objevily i můry.", ExpectedAnswer = "ANO" }, new SubItem { Id = "7.4", Text = "Část odcizených peněz se lupičům cestou z místa činu vysypala, protože zapomněli zamknout zadní dveře auta.", ExpectedAnswer = "ANO" } }, Explanation = "V bodě 7.1 je chyba ve slově 'zhluk', správně se píše shluk (s- hromady, dohromady)." },
                new CermatTask { TaskNumber = "8", Category = TaskCategory.Matching, MaxPoints = 3, Instruction = "Přiřaďte ke každému úryvku tvrzení (A–E), které mu nejlépe odpovídá z hlediska vyprávěcí formy a replik.", Items = new() { new SubItem { Id = "8.1", Text = "Trestankyně kývaly očima, že to pochopily, jen pan strážný ke mně přiskočil: „Číslo vaší legitimace! Tohle je pobuřování!“ Mlčel jsem a otočil se k němu zády.", ExpectedAnswer = "B" }, new SubItem { Id = "8.2", Text = "Nabídl jsem hostovi křeslo a začal rozprávět o všem možném. Pan Záturecký se ale snažil každé slovo vztáhnout na to své pojednání, až jsem nakonec podlehl: „Nic bych neudělal raději, než napsal o vaší práci posudek.“", ExpectedAnswer = "A" }, new SubItem { Id = "8.3", Text = "V domě bylo všecko naruby. Muž se své ženě přiznal, že má poměr. Její reakce byla pochopitelná: „Už s tebou nemůžu žít pod jednou střechou.“ Od té doby uplynuly tři dny. Trpěli jak manželé sami, tak děti a služebnictvo.", ExpectedAnswer = "D" } }, Options = new() { new TaskOption { Label = "A", Text = "Úryvek je vyprávěn v ich-formě, v podtrženém úseku promlouvá postava, která je zároveň vypravěčem." }, new TaskOption { Label = "B", Text = "Úryvek je vyprávěn v ich-formě, v podtrženém úseku promlouvá postava, která není vypravěčem." }, new TaskOption { Label = "C", Text = "Úryvek je vyprávěn v er-formě, v podtrženém úseku promlouvá postava, která je zároveň vypravěčem." }, new TaskOption { Label = "D", Text = "Úryvek je vyprávěn v er-formě, v podtrženém úseku promlouvá postava, která není vypravěčem." }, new TaskOption { Label = "E", Text = "Úryvek je vyprávěn v er-formě, v podtrženém úseku promlouvá jedna ze dvou postav, které se střídají v roli vypravěče." } }, Explanation = "8.1: (ich-forma) Mluví strážný, což není vypravěč (B). 8.2: (ich-forma) Mluví sám vypravěč (A). 8.3: (er-forma) Mluví žena, ne vypravěč (D)." },
                new CermatTask { TaskNumber = "9", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení NEODPOVÍDÁ výchozímu textu (básni)?", TextBase = textBlues, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Podle lyrického subjektu je život pomíjivý." }, new TaskOption { Label = "B", Text = "Podle lyrického subjektu je život jednotvárný." }, new TaskOption { Label = "C", Text = "Lyrický subjekt přirovnává život ke koňským dostihům." }, new TaskOption { Label = "D", Text = "Lyrický subjekt se v souvislosti se ženami zmiňuje o úkladech." } }, Explanation = "Lyrický subjekt popisuje život rozmanitě, jako jízdu v houpačce, na kolečku, dostih i čáru na nebi plnou nástrah a změn (chvíli smích, chvíli pláč), takže jej nepopisuje jako jednotvárný." },
                new CermatTask { TaskNumber = "10", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o básni je pravdivé?", TextBase = textBlues, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "V první části textu je rýmové schéma obou slok totožné, jde o rým střídavý." }, new TaskOption { Label = "B", Text = "V první části textu je rýmové schéma obou slok totožné, nejde ale o rým střídavý." }, new TaskOption { Label = "C", Text = "V druhé části textu je rýmové schéma obou slok totožné, jde o rým střídavý." }, new TaskOption { Label = "D", Text = "V druhé části textu je rýmové schéma obou slok totožné, nejde ale o rým střídavý." } }, Explanation = "V druhé části: (pardubická/klícka a hnát/znát = a-b-a-b) a (tryskáčem/pláčem a rozplyne/ne = c-d-c-d). Obě sloky druhé části mají střídavý rým." },
                new CermatTask { TaskNumber = "11", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve kterém z následujících veršů se nejvýrazněji uplatňuje personifikace?", TextBase = textBlues, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "on mi tu drzost dovolí" }, new TaskOption { Label = "B", Text = "život tě veze na kolečku" }, new TaskOption { Label = "C", Text = "kdo táhne s vlky musí výt" }, new TaskOption { Label = "D", Text = "co si má počít přítel básník" } }, Explanation = "Personifikace oživuje neživé věci (přisuzuje jim lidské vlastnosti). 'Život tě veze...' znamená, že život se zde chová jako bytost, která někoho veze." },
                new CermatTask { TaskNumber = "12", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Vypište: 12.1 z první části textu výraz, který je podstatným jménem, ale jinde může být slovesem; 12.2 z druhé části textu výraz, který je slovesem, ale jinde může být podstatným jménem.", TextBase = textBlues, InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"nevolí", "pláčem"}, Explanation = "12.1 'trpět (kým čím) nevolí' = podstatné jméno. Jako sloveso: 'on nevolí' (od volit). 12.2 'my pláčem' (hovorově pláčeme) = sloveso. Jako podstatné jméno: 's pláčem' (od pláč)." },
                new CermatTask { TaskNumber = "13", Category = TaskCategory.Ordering, MaxPoints = 3, Instruction = "Seřaďte jednotlivé části textu (A–E) tak, aby byla dodržena textová návaznost (K. Abe, Písečná žena).", ExpectedSequence = new() { "B", "D", "A", "E", "C" }, Options = new() { new TaskOption { Label = "A", Text = "Procento těch, kteří se najdou, je ovšem nečekaně malé. Po oběti vraždy většinou zůstanou stopy, stejně tak po nehodě. Při únosu se zase příbuzní dovědí alespoň motiv pachatele." }, new TaskOption { Label = "B", Text = "Tehdy si jistý muž vyjel vlakem na pláž vzdálenou půl dne cesty. Pak už o něm nikdo neslyšel. Když oznámení na policii nemělo úspěch, byl podán inzerát." }, new TaskOption { Label = "C", Text = "Odtamtud ale nepřišlo žádné hlášení, že našli mrtvolu odpovídající jeho popisu. Nepřicházelo v úvahu, že by pomýšlel na útěk nebo že by někomu stál za únos. Když se ani po sedmi letech nic nezjistilo, byl podle § 30 občanského zákoníku prohlášen za nezvěstného a pátrání bylo zastaveno." }, new TaskOption { Label = "D", Text = "Zůstal ale bez odezvy. Ten muž prostě dočista zmizel. Není nic zvláštního, že se někdo ztratí. Statistika říká, že každoročně jsou hlášeny stovky pohřešovaných." }, new TaskOption { Label = "E", Text = "Nejde-li však o žádný z těchto tří případů, je nesmírně obtížné najít nějaké vodítko. Ani při zmizení tohoto muže se nebylo čeho chytit. Jeho blízcí znali jen místo, kam měl namířeno." } }, Explanation = "Muž vyjel, inzerát (B) -> Zůstal bez odezvy, stovky lidí se ztratí (D) -> Najde se jich málo, stopy po třech případech: vraždě, nehodě, únosu (A) -> Žádný z tří případů, blízcí znali místo (E) -> Odtamtud nic, prohlášen za mrtvého (C)." },
                new CermatTask { TaskNumber = "14", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z tvrzení, zda jednoznačně vyplývá z výchozího textu o Přemyslovcích.", TextBase = textPremysl, Items = new() { new SubItem { Id = "14.1", Text = "Napsání Kroniky české si objednali lucemburští panovníci za účelem vlastní propagandy.", ExpectedAnswer = "NE" }, new SubItem { Id = "14.2", Text = "Území, na němž ve 12. století vládli Přemyslovci, bylo ohraničeno z jedné strany horskými hřbety a z opačné strany koryty řek.", ExpectedAnswer = "NE" }, new SubItem { Id = "14.3", Text = "Postava Libuše v pověsti o Přemyslu Oráčovi vyjadřuje ve své řeči jinými slovy totéž, co prorok Samuel v jednom starověkém příběhu.", ExpectedAnswer = "ANO" }, new SubItem { Id = "14.4", Text = "Mýtus o zrodu společenského řádu umožnil přemyslovským vládcům překlenout nepříznivé období, před nímž je varovali kronikáři.", ExpectedAnswer = "NE" } }, Explanation = "14.1 Ne (byla sepsána ve 12. století, Lucemburkové ji až mnohem později VYUŽÍVALI). 14.2 Ne (vymezeno hradbou hor A toky řek, nespecifikuje z jaké strany co). 14.3 Ano ('jde o parafrázi promluvy proroka Samuela'). 14.4 Ne (kronikáři před žádným obdobím nevarovali, naopak samotný mýtus líčí dobu PŘED ním jako chaos)." },
                new CermatTask { TaskNumber = "15", Category = TaskCategory.Correction, MaxPoints = 2, Instruction = "Vypište z druhé části výchozího textu dvě podstatná jména, která jsou příbuzná se slovem ZASLAT.", TextBase = textPremysl, InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedSequence = new() { "vysláním", "poslů" }, Explanation = "Zaslat - poslat - posel - vyslání. Obě podstatná jména pocházejí ze společného kořene (slat/síl/sel)." },
                new CermatTask { TaskNumber = "16", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Na každé ze dvou vynechaných míst (*****) ve výchozím textu patří správné jméno autora. Která jména to jsou?", TextBase = textPremysl, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "Alois Jirásek – Kosmas" }, new TaskOption { Label = "B", Text = "Karel Jaromír Erben – Kosmas" }, new TaskOption { Label = "C", Text = "Alois Jirásek – Václav Hájek z Libočan" }, new TaskOption { Label = "D", Text = "Karel Jaromír Erben – Václav Hájek z Libočan" } }, Explanation = "Autor Starých pověstí českých = Alois Jirásek. Autor (latinské) Kroniky české ze 12. stol. = pražský děkan Kosmas." },
                new CermatTask { TaskNumber = "17", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Který z úseků podtržených ve výchozím textu obsahuje NĚKOLIKANÁSOBNÝ PODMĚT?", TextBase = textPremysl, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "vytvořil tím obraz kořenů a dynastické tradice Přemyslovců" }, new TaskOption { Label = "B", Text = "doba před Přemyslem totiž pro kronikáře představuje chaos a bezpráví" }, new TaskOption { Label = "C", Text = "jež jediná je schopná zaručit spravedlnost a mír v zemi" }, new TaskOption { Label = "D", Text = "důležitá byla také síla a vůle významných českých šlechtických rodů" } }, Explanation = "V D: 'síla a vůle' (kdo, co byla důležitá?) = několikanásobný podmět. Ve zbylých volbách se spojka 'a' objevuje jako součást několikanásobného předmětu nebo přívlastku." },
                new CermatTask { TaskNumber = "18", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Zájmeno KTERÉ, tučně vyznačené ve výchozím textu, je v tomto textu užito v _____ čísle a odkazuje ke slovnímu spojení _____.", TextBase = textPremysl, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "jednotném – knížecí moci" }, new TaskOption { Label = "B", Text = "množném – knížecí moci" }, new TaskOption { Label = "C", Text = "jednotném – výsadní postavení" }, new TaskOption { Label = "D", Text = "množném – výsadní postavení" } }, Explanation = "'knížecí moci (ta moc, rod ženský), které (té moci, 3. pád jednotného čísla) mají být podřízeni'." },
                new CermatTask { TaskNumber = "19", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících možností nejlépe vystihuje výchozí text K. Poláčka?", TextBase = textPolacek, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Pro tento text je příznačné užití jazykových prostředků obecné češtiny." }, new TaskOption { Label = "B", Text = "Pro tento text je příznačné užití jazykových prostředků místního nářečí." }, new TaskOption { Label = "C", Text = "Pro tento text je příznačné užití knižních a archaických jazykových prostředků." }, new TaskOption { Label = "D", Text = "Pro tento text je příznačné užití slangových a argotických jazykových prostředků." } }, Explanation = "Slova jako 'namístě aby', 'respirium', 'povykujíce', 'arcit', 'upozorniti' reprezentují archaismy a knižní výrazy z první poloviny minulého století." },
                new CermatTask { TaskNumber = "20", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Který z následujících spisovatelů nenapsal žádné dílo v době, kdy tvořil Karel Poláček (1. pol. 20. století)?", TextBase = textPolacek, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "John Steinbeck" }, new TaskOption { Label = "B", Text = "Ernest Hemingway" }, new TaskOption { Label = "C", Text = "Erich Maria Remarque" }, new TaskOption { Label = "D", Text = "Johann Wolfgang Goethe" } }, Explanation = "Johann Wolfgang Goethe žil na přelomu 18. a 19. století, s Poláčkem se vůbec neprotnul. Ostatní tvořili v meziválečném či válečném období (20. století)." },
                new CermatTask { TaskNumber = "21", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících vět NENÍ zapsána pravopisně správně?", ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Většinu plochy polární oblasti zvané Arktida tvoří Severní ledový oceán." }, new TaskOption { Label = "B", Text = "Ničivé tornádo zasáhlo jihovýchodní pobřeží Spojených států Amerických." }, new TaskOption { Label = "C", Text = "Po prohlídce Pražského hradu turisté navštívili malebná zákoutí Malé Strany." }, new TaskOption { Label = "D", Text = "Festival v západočeských Karlových Varech každoročně nabízí kvalitní snímky." } }, Explanation = "Spojené státy americké se píšou s malým písmenem u slova 'americké' (není to začátek názvu celku)." },
