                new CermatTask { TaskNumber = "5", Category = TaskCategory.Matching, MaxPoints = 4, Instruction = "Přiřaďte k jednotlivým souvětím odpovídající tvrzení.", Items = new() { new SubItem { Id = "5.1", Text = "Můj otec neumí anglicky, a tak se minulý týden rozhodl, že začne dvakrát týdně chodit do jazykové školy.", ExpectedAnswer = "E" }, new SubItem { Id = "5.2", Text = "Když se jednání chýlilo ke konci, vyjednávací tým přistoupil na některé požadavky, které byly předloženy.", ExpectedAnswer = "F" }, new SubItem { Id = "5.3", Text = "Při úklidu jsem našel pár starých dopisů, napsaných během těch letních prázdnin, kdy jsme se poprvé setkali.", ExpectedAnswer = "B" }, new SubItem { Id = "5.4", Text = "Poslala mu své první povídky, aby získala důležitou zpětnou vazbu, a to především ohledně zvolených témat.", ExpectedAnswer = "A" } }, Options = new() { new TaskOption { Label = "A", Text = "Toto souvětí se skládá ze dvou vět: druhá věta rozvíjí sloveso z první věty." }, new TaskOption { Label = "B", Text = "Toto souvětí se skládá ze dvou vět: druhá věta rozvíjí podstatné jméno z první věty." }, new TaskOption { Label = "C", Text = "Toto souvětí se skládá ze tří vět: druhá věta rozvíjí sloveso z první věty." }, new TaskOption { Label = "D", Text = "Toto souvětí se skládá ze tří vět: druhá věta rozvíjí podstatné jméno z první věty." }, new TaskOption { Label = "E", Text = "Toto souvětí se skládá ze tří vět: třetí věta rozvíjí sloveso z druhé věty." }, new TaskOption { Label = "F", Text = "Toto souvětí se skládá ze tří vět: třetí věta rozvíjí podstatné jméno z druhé věty." } }, Explanation = "5.1: E (rozhodl (co?), že začne). 5.2: F (požadavky, (jaké?), které byly). 5.3: B (dopisů... (jakých dopisů?), kdy jsme se setkali). 5.4: A (poslala (proč?), aby získala)." },
                new CermatTask { TaskNumber = "6", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících tvrzení, zda jednoznačně vyplývá z výchozího textu o rybnících.", TextBase = textRybniky, Items = new() { new SubItem { Id = "6.1", Text = "V minulosti byla v Čechách alespoň nějakou dobu preferována konzumace kaprů před konzumací lososů.", ExpectedAnswer = "ANO" }, new SubItem { Id = "6.2", Text = "Na pozici pomocníka královského porybného se Štěpánkovi Netolickému podařilo prosadit tzv. třístupňový chov ryb.", ExpectedAnswer = "NE" }, new SubItem { Id = "6.3", Text = "Ryby chované v tzv. třístupňovém chovu se k zákazníkům dostaly nejdříve po pěti letech od vylíhnutí potěru v třecím rybníku.", ExpectedAnswer = "NE" }, new SubItem { Id = "6.4", Text = "V 16. století byla denní mzda dělníků pracujících v oboru rybníkářství ve srovnání s dělníky pracujícími v zemědělství více než čtyřnásobná.", ExpectedAnswer = "NE" } }, Explanation = "6.1 Ano (byla dávána přednost před lososy). 6.2 Ne (prosadil to až když byl povýšen). 6.3 Ne (1. rok potěr, 2. rok výtažný, pak další 2-3 roky v největším - celkem 4-5 let, takže se lovily už po čtyřech letech). 6.4 Ne (4-6 grošů vs 1,5 groše není 'více než' 4násobek, maximálně 4násobek)." },
                new CermatTask { TaskNumber = "7", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o zájmenech tučně vyznačených ve výchozím textu (ty, ho) je pravdivé?", TextBase = textRybniky, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "Zájmeno ty odkazuje ke slovu ryby, zájmeno ho odkazuje ke slovu chov." }, new TaskOption { Label = "B", Text = "Zájmeno ty odkazuje ke slovu rybníky, zájmeno ho odkazuje ke slovu chov." }, new TaskOption { Label = "C", Text = "Zájmeno ty odkazuje ke slovu ryby, zájmeno ho odkazuje ke slovu důsledek." }, new TaskOption { Label = "D", Text = "Zájmeno ty odkazuje ke slovu rybníky, zájmeno ho odkazuje ke slovu důsledek." } }, Explanation = "'žily ryby... a chytaly se jen ty největší' (ryby). 'začal se uplatňovat nový chov ryb... Zavedl ho Štěpánek Netolický' (ten chov)." },
                new CermatTask { TaskNumber = "8", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "V souvětí podtrženém ve výchozím textu jsou užita slovesa 'zahájena' a 'podílelo se'. Které z tvrzení o těchto slovesech je pravdivé?", TextBase = textRybniky, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Obě tato slovesa jsou užita v činném rodě." }, new TaskOption { Label = "B", Text = "Obě tato slovesa jsou užita v trpném rodě." }, new TaskOption { Label = "C", Text = "Sloveso zahájit je užito v činném rodě, sloveso podílet se je užito v trpném rodě." }, new TaskOption { Label = "D", Text = "Sloveso zahájit je užito v trpném rodě, sloveso podílet se je užito v činném rodě." } }, Explanation = "'byla zahájena' je trpný rod (opisný). 'podílelo se' je činný rod (zvratné sloveso)." },
                new CermatTask { TaskNumber = "9", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o úseku zapsaném ve výchozím textu velkými písmeny je pravdivé?", TextBase = textRybniky, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Slovo strava je v tomto úseku významově nadřazené pouze jednomu slovu, a to chleba." }, new TaskOption { Label = "B", Text = "Slovo strava je v tomto úseku významově nadřazené celkem dvěma slovům, a to pivo a chleba." }, new TaskOption { Label = "C", Text = "Slovo strava je v tomto úseku významově nadřazené celkem dvěma slovům, a to žejdlík a chleba." }, new TaskOption { Label = "D", Text = "Slovo strava je v tomto úseku významově nadřazené celkem třem slovům, a to žejdlík, pivo a chleba." } }, Explanation = "Pod pojmem 'strava' se zde myslí 'pivo' a 'chleba'. Žejdlík je pouze měrná jednotka objemu." },
                new CermatTask { TaskNumber = "10", Category = TaskCategory.Correction, MaxPoints = 3, Instruction = "Vypište z druhé části výchozího textu (odstavce 2) TŘI podstatná jména rodu středního, která jsou v 1. pádě čísla jednotného TŘÍSLABIČNÁ.", TextBase = textRybniky, InputFieldsCount = 3, UserInputs = new string[] { "", "", "" }, ExpectedSequence = new() { "století", "okolí", "stadiu" }, Explanation = "To století (sto-le-tí), to okolí (o-ko-lí), to stadium (sta-di-um)." },
                new CermatTask { TaskNumber = "11", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících souvětí, zda je zapsáno pravopisně SPRÁVNĚ.", Items = new() { new SubItem { Id = "11.1", Text = "Havraní vlasy jí padaly z čela a jemně se dotýkaly jejích sněhobílých ramen.", ExpectedAnswer = "ANO" }, new SubItem { Id = "11.2", Text = "Pokud to alespoň nezkusíš, nikdy se svému vytouženému cíli ani nepřiblížíš.", ExpectedAnswer = "ANO" }, new SubItem { Id = "11.3", Text = "Hliněnné domky na okraji vsi byly sice prosté, ale poskytovaly turistům dostatek soukromí.", ExpectedAnswer = "NE" }, new SubItem { Id = "11.4", Text = "Pohled ze Šumavy nám bohužel dosud nepřišel, protože sestra zřejmně napsala špatné směrovací číslo.", ExpectedAnswer = "NE" } }, Explanation = "11.3: Má být 'hliněné' (hlína + ěné). 11.4: Má být 'zřejmě' (od zřejmý, neobsahuje n)." },
                new CermatTask { TaskNumber = "12", Category = TaskCategory.Filling, MaxPoints = 1, Instruction = "Na vynechané místo (*****) v české pranostice doplňte příslušné sloveso v náležitém tvaru.", TextBase = "Lucie noci <b>[ ***** ]</b>, ale dne nepřidá.", InputFieldsCount = 1, UserInputs = new[] {""}, ExpectedInputs = new[] {"upije"}, Explanation = "Pranostika zní: Svatá Lucie noci upije, ale dne nepřidá." },
                new CermatTask { TaskNumber = "13", Category = TaskCategory.Ordering, MaxPoints = 3, Instruction = "Seřaďte jednotlivé části textu (A–F) tak, aby byla dodržena textová návaznost (Vládkyně koření).", ExpectedSequence = new() { "E", "B", "D", "C", "A", "F" }, Options = new() { new TaskOption { Label = "A", Text = "Pak je pustila, o krok ustoupila a povzdechla si. Věděla jsem, že Bába každým rokem posílá z ostrova domů spoustu dívek, protože nemají správné ruce." }, new TaskOption { Label = "B", Text = "Moře ze mě všechno servalo – šaty, kouzla, a dokonce i drzost. Zahanbeně jsem si stahovala dlouhé vlasy, abych alespoň trochu zakryla své tělo. Ale Bába už sňala svůj šál a dala mi ho kolem ramen." }, new TaskOption { Label = "C", Text = "Neuměla jsem jí odpovědět. Mé jméno vybledlo ve vycházejícím ostrovním slunci jako hvězda včerejší noci. Choulila jsem se do šálu a beze slova jsem na ni zírala. „Ukaž,“ řekla mi a vzala mé ruce do svých dlaní." }, new TaskOption { Label = "D", Text = "Byl měkký a šedivý jako peříčka hrdličky. Obklopila mě vůně koření a kouzel, jež jsem se toužila naučit. Bába si mě zvědavě prohlížela: „Jak se jmenuješ, dítě?“" }, new TaskOption { Label = "E", Text = "„Copak nám to dnes bůh moří vyvrhnul na břeh?“ pronesla ke mně Bába. Uctivě jsem před ní poklekla. Teprve teď jsem si všimla, že jsem nahá." }, new TaskOption { Label = "F", Text = "Nepomůže jim ani to, že dokážou létat po obloze. Mohla jsem být jednou z nich, nebýt mých kostí. Proto mě nechala na ostrově, i když jí zdravý rozum velel nedělat to. Kosti jsou totiž pro dobré ruce nejdůležitější." } }, Explanation = "Představení u moře (E) -> přikrytí šálem (B) -> popis šálu a dotaz na jméno (D) -> nevím jméno a chycení rukou (C) -> povzdech a pouštění domů dívek kvůli špatným rukám (A) -> vysvětlení, proč mě si Bába nechala (F)." },
                new CermatTask { TaskNumber = "14", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících možností nejlépe vystihuje výchozí text o seriálu Joey?", TextBase = "Spin-off Joey je oproti svému legendárnímu předchůdci opravdu slabým odvarem. Postava se sice jmenuje stejně, Matt LeBlanc odvádí víceméně podobný výkon jako v seriálu Přátelé, ale sám naprosto nemá šanci utáhnout celý seriál. Znatelně tu chybí špičkování s Chandlerem (vzpomeňte si na slavnou scénu s krocanem) nebo vylomeniny s potrhlou Phoebe. Nového Joeyho by zkrátka nezachránily ani kuře s kachnou.", ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "Tento text, jehož účelem je zhodnotit spin-off Joey, je adresován čtenáři, který se v dané oblasti alespoň trochu orientuje." }, new TaskOption { Label = "B", Text = "Tento text, jehož účelem je zhodnotit spin-off Joey, je adresován nezasvěcenému čtenáři, jenž všechny potřebné informace získá až po přečtení textu." }, new TaskOption { Label = "C", Text = "Tento text, jehož účelem je formou pozitivního komentáře doporučit spin-off Joey, je adresován čtenáři, který se v dané oblasti alespoň trochu orientuje." }, new TaskOption { Label = "D", Text = "Tento text, jehož účelem je formou pozitivního komentáře doporučit spin-off Joey, je adresován nezasvěcenému čtenáři, jenž všechny potřebné informace získá až po přečtení textu." } }, Explanation = "Text předpokládá znalost původního seriálu Přátelé (odkazuje na scénu s krocanem, Phoebe, kuře s kachnou). Nejedná se o doporučení, naopak říká, že je to 'slabý odvar'." },
                new CermatTask { TaskNumber = "15", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která možnost je gramaticky správnou větou jednoduchou zachovávající význam souvětí: 'Tato budova, která dnes slouží jako umělecká galerie, je jednou z nejzajímavějších staveb minulého století.'?", ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Tato budova, dnes sloužící jako umělecká galerie, jedna z nejzajímavějších staveb minulého století." }, new TaskOption { Label = "B", Text = "Tato budova dnes slouží jako umělecká galerie a jednou z nejzajímavějších staveb minulého století." }, new TaskOption { Label = "C", Text = "Tato budova, jedna z nejzajímavějších staveb minulého století, dnes slouží jako umělecká galerie." }, new TaskOption { Label = "D", Text = "Tato budova je jednou z nejzajímavějších staveb minulého století a dnes sloužící jako umělecká galerie." } }, Explanation = "C obsahuje přístavek ('jedna z nejzajímavějších staveb') a hlavní přísudek ('slouží'). Jde o větu jednoduchou bez ztráty smyslu. Varianta A nemá přísudek, B a D jsou gramaticky chybné/nesmyslné konstrukce." },
                new CermatTask { TaskNumber = "16", Category = TaskCategory.Correction, MaxPoints = 4, Instruction = "Najděte ve výchozím textu o lázních ČTYŘI slova zapsaná s pravopisnou chybou a napište je pravopisně SPRÁVNĚ.", TextBase = textLazne, InputFieldsCount = 4, UserInputs = new string[] { "", "", "", "" }, ExpectedSequence = new() { "významně", "typickou", "sjížděly", "trojúhelník" }, Explanation = "významě -> významně (od významný). tipickou -> typickou (vyjmenované slovo). sjížděli -> sjížděly (osobnosti - rod ženský mn. č. -> tvrdé y). trojůhelník -> trojúhelník (ú se píše i uprostřed, pokud je slovo složené z 'troj' a 'úhel')." },
                new CermatTask { TaskNumber = "17", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Vytvořte a napište dvě podstatná jména podle zadaných kritérií.", TextBase = "17.1 1. pád j.č. dvouslabičné, příbuzné se slovem SMÍCH, vzor HRAD, s předponou.\n17.2 1. pád j.č. dvouslabičné, příbuzné se slovem UČIT, vzor MUŽ, bez předpony.", InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"výsměch", "učeň"}, Explanation = "17.1 vý-směch nebo ú-směv (obě jako hrad). 17.2 u-čeň (ten učeň jako ten muž)." },
                new CermatTask { TaskNumber = "18", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z tvrzení, zda jednoznačně vyplývá z TEXTU 1 (o Drážďanech).", TextBase = textDrazdany, Items = new() { new SubItem { Id = "18.1", Text = "Alespoň jeden z rodičů Jeroma má sourozence.", ExpectedAnswer = "ANO" }, new SubItem { Id = "18.2", Text = "Drážďany byly první zastávkou na cestě, kterou George a jeho dva přátelé podnikli.", ExpectedAnswer = "NE" }, new SubItem { Id = "18.3", Text = "George začal příhodu, kterou zažil v krámku poblíž nádraží, vyprávět svému příteli někdy během sobotního večera.", ExpectedAnswer = "ANO" }, new SubItem { Id = "18.4", Text = "George prohlásil, že na základě prvního dojmu očekával, že upejpavá dívenka bude vykonávat jinou profesi, než je prodavačka.", ExpectedAnswer = "NE" } }, Explanation = "18.1: Ano, Jerome je synovec, takže jeho rodič musí mít sourozence (kterému Jerome říká teto/strýčku). 18.2: Ne, 'z každého města jí poslal dárek' naznačuje, že měst už bylo více. 18.3: Ano, 'Až krátce po setmění [v sobotu]... George spustil:'. 18.4: Ne, řekl že by nečekal, 'že něco takového udělají', nikoliv že by dělaly jinou profesi." },
                new CermatTask { TaskNumber = "19", Category = TaskCategory.Correction, MaxPoints = 3, Instruction = "Vypište z DRUHÉ ČÁSTI TEXTU 1 (začínající 'Poslouchej...') tři shodné přívlastky.", TextBase = textDrazdany, InputFieldsCount = 3, UserInputs = new string[] { "", "", "" }, ExpectedSequence = new() { "té", "německé", "žádný" }, Explanation = "té (slečně), německé (slovíčko), žádný (důvod)." },
                new CermatTask { TaskNumber = "20", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve které z možností je uvedena dvojice slov, jež jsou v kontextu TEXTU 1 antonymy?", TextBase = textDrazdany, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "stejně - odlišně" }, new TaskOption { Label = "B", Text = "obyčejně - neobyčejně" }, new TaskOption { Label = "C", Text = "srozumitelně - nesrozumitelně" }, new TaskOption { Label = "D", Text = "poněkud - trochu" } }, Explanation = "Srozumitelně a nesrozumitelně jsou jasná antonyma (slova opačného významu). V textu je sice 'stejně, obyčejně, srozumitelně, poněkud', ale slovo 'stejně' zde znamená 'i tak', slovo 'obyčejně' znamená 'obvykle'. 'Poněkud' a 'trochu' jsou synonyma." },
                new CermatTask { TaskNumber = "21", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o dvou úsecích podtržených v TEXTU 1 je pravdivé?", TextBase = textDrazdany, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "V prvním úseku George reprodukuje promluvu dívky, v druhém úseku reprodukuje pomocí přímé řeči svou promluvu." }, new TaskOption { Label = "B", Text = "V prvním úseku George reprodukuje slova, jimiž reaguje na dívku, v druhém úseku reprodukuje pomocí přímé řeči svou promluvu." }, new TaskOption { Label = "C", Text = "V prvním úseku George reprodukuje promluvu dívky, v druhém úseku reprodukuje pomocí nepřímé řeči slova, jimiž reaguje na Jeroma." }, new TaskOption { Label = "D", Text = "V prvním úseku George reprodukuje slova, jimiž reaguje na dívku, v druhém úseku reprodukuje pomocí nepřímé řeči slova, jimiž reaguje na Jeroma." } }, Explanation = "První úsek 'co prý si přeju' reprodukuje to, co řekla dívka (nepřímá řeč s 'prý'). Druhý úsek 'Dostanu ho, povídám jí' je přímá reprodukce jeho vlastní řeči." },
                new CermatTask { TaskNumber = "22", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve kterém z úseků TEXTU 1 se vyskytuje NESKLONNÉ podstatné jméno? (Na základě definice v TEXTU 2)", TextBase = textDrazdany, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "mám v tom docela praxi" }, new TaskOption { Label = "B", Text = "podle mého mínění to dost přehání" }, new TaskOption { Label = "C", Text = "že jsem na pultu nechal ležet svou bankovku" }, new TaskOption { Label = "D", Text = "když jsem s ním v našem apartmá zůstal o samotě" } }, Explanation = "Slovo 'apartmá' zůstává stejné ve všech pádech (to apartmá, bez apartmá, v apartmá). Jde o nesklonné přejaté slovo zakončené na samohlásku." },
                new CermatTask { TaskNumber = "23", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících možností nejlépe vystihuje TEXT 1?", TextBase = textDrazdany, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Pro tento text platí: vykazuje znaky nonsensové literatury a jeho součástí je detailní popis polštářků." }, new TaskOption { Label = "B", Text = "Pro tento text platí: vykazuje znaky humoristické literatury a jeho součástí je detailní popis polštářků." }, new TaskOption { Label = "C", Text = "Pro tento text platí: vykazuje znaky nonsensové literatury a detailní popis polštářků není jeho součástí." }, new TaskOption { Label = "D", Text = "Pro tento text platí: vykazuje znaky humoristické literatury a detailní popis polštářků není jeho součástí." } }, Explanation = "Je to komická situace (omyl s německým slovem pro polštář), nejedná se o nonsens (nesmyslnou poezii). Žádný detailní popis polštářků se v ukázce nevyskytuje." },
                new CermatTask { TaskNumber = "24", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve kterém z následujících větných celků je správně zapsána interpunkce?", ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Řada lidí, kteří veřejně vystupují naše výrobky, často využívá při práci." }, new TaskOption { Label = "B", Text = "Zejména ve chvílích, kdy jsme smutní, zaujímáme schoulený tělesný postoj." }, new TaskOption { Label = "C", Text = "Rozhodni se včas, ideálně ještě dnes lístky na zápas, budou brzy vyprodané." }, new TaskOption { Label = "D", Text = "Po těch zmatcích při odbavování, ho už nedonutíš, aby příště cestoval letadlem." } }, Explanation = "V B je vložená věta vedlejší 'kdy jsme smutní' správně oddělena čárkami z obou stran." },
