                new CermatTask { TaskNumber = "1", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících úprav odstraní pravopisnou chybu z výchozího textu?", TextBase = "Před odjezdem mi kamarádi připoměli, abych s sebou sbalila nějaké deskové hry.", ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "když místo mi napíšeme my" }, new TaskOption { Label = "B", Text = "když místo připoměli napíšeme připomněli" }, new TaskOption { Label = "C", Text = "když místo s sebou napíšeme sebou" }, new TaskOption { Label = "D", Text = "když místo sbalila napíšeme zbalila" } }, Explanation = "Slovo 'připomněli' se píše s 'mně' (od slova pomněnka, zapomněl, vzpomněl)." },
                new CermatTask { TaskNumber = "2", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení odpovídá výchozímu textu o kobylce a gnómovi?", TextBase = textKobylka, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Jakmile kobylka pod houbou oschla, začala o sobě před gnómem tvrdit, že má fantastický zjev." }, new TaskOption { Label = "B", Text = "Gnóm se rozesmál až poté, co kobylku ukrytou pod houbou úmyslně zašlápl kolemjdoucí pytlák." }, new TaskOption { Label = "C", Text = "Během bouřky byl gnóm na rozdíl od kobylky skoupý na slovo, jakmile však přestalo pršet, jejich role se obrátily." }, new TaskOption { Label = "D", Text = "Kobylka se gnómovi posmívala, přičemž terčem jejího posměchu byl mimo jiné gnómův oděv včetně jeho čapky s rolničkou." } }, Explanation = "Ve slocích se píše: 'tropila sobě z gnóma smíchy: háv jeho pestrý, brada bílá a jak drahokam lampička... i rolnička na čapce lesklá jí k smíchu byly'." },
                new CermatTask { TaskNumber = "3", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o dvou verších podtržených ve výchozím textu je pravdivé?", TextBase = textKobylka, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "V každém z těchto veršů se vyskytuje přirovnání." }, new TaskOption { Label = "B", Text = "V žádném z těchto veršů se nevyskytuje přirovnání." }, new TaskOption { Label = "C", Text = "Přirovnání se vyskytuje ve verši z první části textu, nikoli však ve verši z druhé části textu." }, new TaskOption { Label = "D", Text = "Přirovnání se vyskytuje ve verši z druhé části textu, nikoli však ve verši z první části textu." } }, Explanation = "Oba podtržené verše obsahují přirovnání se spojkou 'jako'/'jak': 'jak drahokam lampička' a 'lehký jako stín'." },
                new CermatTask { TaskNumber = "4", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o výrazu 'jí' je pravdivé? (Věty s posuzovaným výrazem jsou gramaticky správné.)", TextBase = textKobylka, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Výraz jí je jak ve výchozím textu, tak ve větě 'Jogurt jí k snídani nestačí' tvarem slovesa." }, new TaskOption { Label = "B", Text = "Výraz jí je jak ve výchozím textu, tak ve větě 'Jogurt jí k snídani nestačí' tvarem zájmena." }, new TaskOption { Label = "C", Text = "Výraz jí je ve výchozím textu tvarem slovesa, ale ve větě 'Jogurt jí k snídani nestačí' je tvarem zájmena." }, new TaskOption { Label = "D", Text = "Výraz jí je ve výchozím textu tvarem zájmena, ale ve větě 'Jogurt jí k snídani nestačí' je tvarem slovesa." } }, Explanation = "V básni 'jí k smíchu byly' znamená komu čemu jí (zájmeno ona ve 3. pádě). Ve větě 'Jogurt jí k snídani nestačí' je to opět komu čemu jí (zájmeno)." },
                new CermatTask { TaskNumber = "5", Category = TaskCategory.Matching, MaxPoints = 4, Instruction = "Přiřaďte k jednotlivým větám odpovídající tvrzení o podmětu a přísudku.", Items = new() { new SubItem { Id = "5.1", Text = "Nedávno jsme v zoo viděli jak nově narozené vlčí mládě, tak několikaměsíční medvíďata.", ExpectedAnswer = "A" }, new SubItem { Id = "5.2", Text = "Nejen většině dospělých, ale i jejich dětem se nejvíc líbila nenáročná túra k vodopádům.", ExpectedAnswer = "E" }, new SubItem { Id = "5.3", Text = "Ještě koncem minulého století byl tento stát největším producentem čaje a kávy na světě.", ExpectedAnswer = "F" }, new SubItem { Id = "5.4", Text = "Vodácké kempy i místní restaurace jsou letos kvůli dlouhodobému suchu nezvykle prázdné.", ExpectedAnswer = "D" } }, Options = new() { new TaskOption { Label = "A", Text = "Tato věta obsahuje podmět nevyjádřený a přísudek slovesný." }, new TaskOption { Label = "B", Text = "Tato věta obsahuje podmět nevyjádřený a přísudek jmenný se sponou." }, new TaskOption { Label = "C", Text = "Tato věta obsahuje podmět vyjádřený, a to několikanásobný, a přísudek slovesný." }, new TaskOption { Label = "D", Text = "Tato věta obsahuje podmět vyjádřený, a to několikanásobný, a přísudek jmenný se sponou." }, new TaskOption { Label = "E", Text = "Tato věta obsahuje podmět vyjádřený, nikoli však několikanásobný, a přísudek slovesný." }, new TaskOption { Label = "F", Text = "Tato věta obsahuje podmět vyjádřený, nikoli však několikanásobný, a přísudek jmenný se sponou." } }, Explanation = "5.1: (my) viděli (nevyjádřený, slovesný). 5.2: túra se líbila (vyjádřený 1, slovesný). 5.3: stát byl producentem (vyjádřený 1, jmenný). 5.4: kempy i restaurace jsou prázdné (vyjádřený několikanásobný, jmenný)." },
                new CermatTask { TaskNumber = "6", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících tvrzení, zda jednoznačně vyplývá z TEXTU 1 (Peníze).", TextBase = textPenize, Items = new() { new SubItem { Id = "6.1", Text = "Alespoň po určitou část období 1570–1045 př. n. l. byly v Číně platidlem mušle kauri.", ExpectedAnswer = "ANO" }, new SubItem { Id = "6.2", Text = "Tenkými plíšky rozličných tvarů se platilo již před rokem 4000 př. n. l., tedy dříve než mincemi.", ExpectedAnswer = "ANO" }, new SubItem { Id = "6.3", Text = "Průměrná velikost peněz zvaných rai, které se používaly k placení na ostrově Yap, byla čtyři metry.", ExpectedAnswer = "NE" }, new SubItem { Id = "6.4", Text = "Všechny peníze zvané rai, které se ve 30. letech 20. století nacházely na ostrově Yap, byly podle některých odborníků staré minimálně 500 let.", ExpectedAnswer = "NE" } }, Explanation = "6.1: Ano, platilo se jimi během vlády dynastie Šang. 6.2: Ano, v Mezopotámii už v 5. tisíciletí př. n. l., mince vznikly až koncem 7. století. 6.3: Ne, největší z nich měly 4 metry, nikoliv průměrně všechny. 6.4: Ne, text říká, že se používaly 'nejméně pět set let', ne že všechny zachované kusy byly tak staré." },
                new CermatTask { TaskNumber = "7", Category = TaskCategory.Correction, MaxPoints = 3, Instruction = "Vypište z druhé části TEXTU 1 tři dvouslabičná podstatná jména, která jsou v textu užita ve 4. pádě. (Slova kauri a Šang neposuzujte).", TextBase = textPenize, InputFieldsCount = 3, UserInputs = new string[] { "", "", "" }, ExpectedSequence = new() { "plíšky", "cenu", "množství" }, Explanation = "Plíšky (šlo o koho co: plíšky - 4. pád, plíš-ky), cenu (měl koho co: cenu - 4. pád, ce-nu), množství (směnili za koho co: množství - 4. pád, množ-ství)." },
                new CermatTask { TaskNumber = "8", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o dvou úsecích zapsaných v TEXTU 1 velkými písmeny je pravdivé? (Řešte na základě TEXTU 2).", TextBase = textPenize, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Každý z těchto úseků by měl být oddělen čárkami, neboť v obou případech jde o přívlastek volný." }, new TaskOption { Label = "B", Text = "Žádný z těchto úseků by neměl být oddělen čárkami, neboť v obou případech jde o přívlastek těsný." }, new TaskOption { Label = "C", Text = "První úsek je přívlastek volný, a proto by měl být oddělen čárkami. Druhý úsek je přívlastek těsný, a proto by neměl být oddělen." }, new TaskOption { Label = "D", Text = "První úsek je přívlastek těsný, a proto by neměl být oddělen čárkami. Druhý úsek je přívlastek volný, a proto by měl být oddělen." } }, Explanation = "Přívlastky 'týkající se českých platidel' a 'zabývající se původem slov' jsou těsné (zužují význam daného podstatného jména zmínka / publikace a nelze je vynechat bez změny smyslu věty). Neoddělují se čárkami." },
                new CermatTask { TaskNumber = "9", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o zájmenech tučně vyznačených v TEXTU 1 (ně, jejichž) je pravdivé?", TextBase = textPenize, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Zájmeno ně odkazuje ke slovu zboží, zájmeno jejichž odkazuje ke slovu hlíny." }, new TaskOption { Label = "B", Text = "Zájmeno ně odkazuje ke slovu výhrad, zájmeno jejichž odkazuje ke slovu hlíny." }, new TaskOption { Label = "C", Text = "Zájmeno ně odkazuje ke slovu zboží, zájmeno jejichž odkazuje ke slovu předměty." }, new TaskOption { Label = "D", Text = "Zájmeno ně odkazuje ke slovu výhrad, zájmeno jejichž odkazuje ke slovu předměty." } }, Explanation = "'dá vám za NĚ (to zboží) to své' a 'předměty z hlíny, JEJICHŽ (těch předmětů) hodnotu určoval tvar'." },
                new CermatTask { TaskNumber = "10", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve které z možností jsou významové vztahy mezi slovy nejpodobnější vztahům mezi slovy STŘÍBRO – MINCE – PLATIT? (Z textu: materiál - výrobek - účel)", TextBase = textPenize, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "chleba – pec – jíst" }, new TaskOption { Label = "B", Text = "papír – brčko – pít" }, new TaskOption { Label = "C", Text = "sklo – okno – opravit" }, new TaskOption { Label = "D", Text = "dům – beton – postavit" } }, Explanation = "Stříbro je materiál, ze kterého se vyrobí mince a tou se platí. Papír je materiál, ze kterého se vyrobí brčko a tím se pije." },
