                new CermatTask { TaskNumber = "12", Category = TaskCategory.Ordering, MaxPoints = 3, Instruction = "Seřaďte jednotlivé části textu (A–F) tak, aby byla dodržena textová návaznost (Příběh tvého života).", ExpectedSequence = new() { "F", "A", "C", "B", "E", "D" }, Options = new() { new TaskOption { Label = "A", Text = "„Pan plukovník Weber, nemýlím-li se,“ oslovila jsem toho vojáka a potřásla jsem si s ním rukou, „těší mě, Louisa Banksová.“ „Dobrý den, paní doktorko,“ řekl Weber, „tohle je doktor Donnelly.“ Společně jsme vešli do mé pracovny." }, new TaskOption { Label = "B", Text = "Weber si poposedl, vyndal z aktovky magnetofon a stiskl přehrávání. Znělo to, jako když si mokrý pes vytřásá z kožichu vodu. „Co vy na to?“ zeptal se mě." }, new TaskOption { Label = "C", Text = "Sundala jsem pár komínků knížek ze židlí pro hosty a všichni jsme se posadili. „Říkal jste, že chcete, abych si poslechla nějakou nahrávku. Předpokládám, že se to týká mimozemšťanů.“" }, new TaskOption { Label = "D", Text = "„Nemám svolení vám na to odpovědět. Mohu vám poskytnout jen tuto nahrávku,“ prohlásil plukovník. „Nic přece neprozradíte, když řeknete, že jste viděli mimozemšťana,“ naléhala jsem. S ním to ale ani nehnulo: „Máte nějaký názor na jazykový charakter nahrávky, kterou jste právě slyšela?“" }, new TaskOption { Label = "E", Text = "„V jakých souvislostech to bylo nahráno?“ zajímalo mě. „Pomohlo by to s interpretací zvuků. Viděli jste mimozemšťana, když mluvil? Co u toho dělal?“" }, new TaskOption { Label = "F", Text = "Čekali na chodbě před mojí pracovnou. Byla to zvláštní dvojice. Jeden ve vojenské uniformě, ten druhý vypadal jako univerzitní profesor." } }, Explanation = "F (Čekali na chodbě) -> A (Oslovení plukovníka) -> C (Posazení a téma nahrávky) -> B (Puštění magnetofonu) -> E (Zájem o souvislosti nahrávky a mimozemšťana) -> D (Odmítnutí poskytnout detaily)." },
                new CermatTask { TaskNumber = "13", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících možností nejlépe vystihuje text o seriálu The Boys?", TextBase = "V červnu 2024 odstartovala čtvrtá řada amerického seriálu The Boys... Očekávanou dávku satiry sice dostanete, ve většině dílů se ale děj nijak neposouvá dopředu. Naštěstí Antony Starr je v roli labilního Homelandera čím dál zvrácenější a spousta hlášek Deepa vás zaručeně odrovná, takže i tahle řada stojí za to.", ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Autor textu uvádí nejen fakta, ale i své názory, v žádné pasáži se však na čtenáře přímo neobrací." }, new TaskOption { Label = "B", Text = "Autor textu uvádí pouze své názory, nikoli fakta, v žádné pasáži se však na čtenáře přímo neobrací." }, new TaskOption { Label = "C", Text = "Autor textu uvádí nejen fakta, ale i své názory a v některých pasážích se přímo obrací na čtenáře." }, new TaskOption { Label = "D", Text = "Autor textu uvádí pouze své názory, nikoli fakta a v některých pasážích se přímo obrací na čtenáře." } }, Explanation = "Fakta (červená 2024, čtvrtá řada), názory (děj se neposouvá, herec je zvrácenější), přímé obrácení na čtenáře ('dostanete', 'vás zaručeně odrovná')." },
                new CermatTask { TaskNumber = "14", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Pro které z následujících souvětí platí tvrzení: Obsah první věty a obsah druhé věty se navzájem vylučují, třetí věta rozvíjí druhou větu?", ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Vyber si buď křupky, nebo chipsy, hlavně už přestaň vykřikovat, dost nás to totiž otravuje." }, new TaskOption { Label = "B", Text = "Když při sledování filmu stále povídáš, nebo dokonce vykřikuješ, dost nás to otravuje." }, new TaskOption { Label = "C", Text = "Vyber si buď křupky, nebo chipsy, hlavně už přestaň vykřikovat, co se bude dít v další scéně." }, new TaskOption { Label = "D", Text = "Ty při sledování filmu buď hned usneš, nebo neustále vykřikuješ, co se bude dít v další scéně." } }, Explanation = "Ve větě D je poměr vylučovací (buď usneš, nebo vykřikuješ). Třetí věta 'co se bude dít' rozvíjí druhou větu 'vykřikuješ' (vykřikuješ koho co?)." },
                new CermatTask { TaskNumber = "15", Category = TaskCategory.Correction, MaxPoints = 4, Instruction = "Najděte ve výchozím textu o Tereze ČTYŘI slova, která jsou v něm zapsána s pravopisnou chybou, a napište je pravopisně správně.", TextBase = textTereza, InputFieldsCount = 4, UserInputs = new string[] { "", "", "", "" }, ExpectedSequence = new() { "raného", "prohloubil", "zaměřením", "shrnula" }, Explanation = "ranného -> raného (od slova raný = brzký, ne ráno), prohloubyl -> prohloubil (měkké i), zamněřením -> zaměřením (od míra, bez n), zhrnula -> shrnula (dohromady -> s)." },
                new CermatTask { TaskNumber = "16", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Vytvořte a napište dvě podstatná jména podle zadaných kritérií.", TextBase = "16.1 1. pád j.č. tříslabičné, příbuzné se slovem ŽIVOT, vzor KOST, bez předpony.\n16.2 1. pád j.č. jednoslabičné, příbuzné se slovem RODIT, vzor HRAD, s předponou.", InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"životnost", "zrod"}, Explanation = "16.1 živ-ot-nost (ta životnost jako kost). 16.2 z-rod (ten zrod jako hrad)." },
                new CermatTask { TaskNumber = "17", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících tvrzení, zda jednoznačně vyplývá z TEXTU 1 (Město netvorů).", TextBase = textNetvor, Items = new() { new SubItem { Id = "17.1", Text = "V Katině bytě se nacházely upomínkové předměty z celkem dvou zemí.", ExpectedAnswer = "NE" }, new SubItem { Id = "17.2", Text = "Kate sdělila Alexovi, že netvor začne pronikavě zapáchat, jakmile se octne poblíž lidí či zvířat.", ExpectedAnswer = "NE" }, new SubItem { Id = "17.3", Text = "Dům v blíže nespecifikované newyorské čtvrti, v němž bydlela Kate Coldová, byl jedenáctipatrový.", ExpectedAnswer = "NE" }, new SubItem { Id = "17.4", Text = "Alex se setkal se svou babičkou až po půlnoci, protože cesta z letiště do Katina bytu mu trvala šest hodin.", ExpectedAnswer = "NE" } }, Explanation = "17.1: Ne, text zmiňuje předměty z RŮZNÝCH zemí a konkrétně dvě uvádí jen jako příklad, který ho zaujal. 17.2: Ne, páchne prostě pronikavě (pořád). 17.3: Ne, víme, že vystoupil v 11. patře, ne že to bylo poslední patro. 17.4: Ne, text říká, že vydrží 6 hodin trénovat, ne že 6 hodin šel z letiště." },
                new CermatTask { TaskNumber = "18", Category = TaskCategory.Correction, MaxPoints = 3, Instruction = "Vypište z DRUHÉ ČÁSTI TEXTU 1 (od slova „Myslíš, že je...“) TŘI příslovečná určení způsobu.", TextBase = textNetvor, InputFieldsCount = 3, UserInputs = new string[] { "", "", "" }, ExpectedSequence = new() { "tiše", "s elegancí", "jízlivě" }, Explanation = "Jak zláme kosti? Tiše. Jak je vykuchá? S elegancí. Jak odsekla Kate? Jízlivě." },
