        private List<CermatTask> GetC9A2025()
        {
            string textPoetry = @"<div class='bg-slate-100 dark:bg-slate-900/50 p-5 rounded-2xl border border-slate-200 dark:border-white/5'>
                <h4 class='text-[10px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-4'>Text 1 (Básník)</h4>
                <p class='whitespace-pre-line italic text-slate-800 dark:text-slate-300 leading-relaxed text-sm md:text-base'>Bydlí někde v podkroví,
                přitom sotva odpoví
                správcové, co otvírá mu,
                když se vrací domů k ránu
                tenhle básník z podkroví.
                
                Vždycky mu to závidím,
                že na všechno najde rým.
                A tak když ho potkám k ránu,
                jak se vrací domů z flámu,
                váhavě ho oslovím:
                
                „Básníku, já hledám rým,
                podaruj mě některým,
                přece nebude ti
                až tolik chyběti
                ten jediný, co bude mým...“
                
                „<u>Paní</u>, vy jste <u>popleta,</u>“
                povídá ten poeta,
                „kdyby každý rým
                měl být soukro-rým,
                zmizí básně ze světa.
                
                <b>Nejde přece, jak se říká,
                psát ty básně do šuplíka,</b>
                nezazáří rým ve snáři
                ani sušený v herbáři.
                
                A ti, co mi závidí,
                zaručeně nevidí,
                že ty všechny rýmy
                vlastně nepatří mi,
                protože je dělám pro lidi...“</p>
                <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium'>(J. Jakoubek, Básník, upraveno)</p>
            </div>";

            string textTypAB = @"<div class='bg-slate-100 dark:bg-slate-900/50 p-5 rounded-2xl border border-slate-200 dark:border-white/5'>
                <h4 class='text-[10px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-4'>Text 2</h4>
                <p class='mb-4 text-slate-800 dark:text-slate-300 text-sm md:text-base'><b>U podstatného jména typu A</b> (např. průvodčí, choť) nelze ze samotného tvaru 1. pádu čísla jednotného určit, zda toto slovo je rodu mužského životného, nebo rodu ženského. Kterou osobu má mluvčí na mysli, poznáme až při skloňování nebo z kontextu, např. s <i>průvodčí</i> × s <i>průvodčím</i>; moje <i>choť</i> Jana × můj <i>choť</i> Petr.</p>
                <p class='text-slate-800 dark:text-slate-300 text-sm md:text-base'><b>U podstatného jména typu B</b> (např. číšník, vědkyně) lze ze samotného tvaru 1. pádu čísla jednotného určit, zda toto slovo je rodu mužského životného, nebo rodu ženského.</p>
            </div>";

            string textZvony = @"<div class='columns-1 lg:columns-2 gap-8 space-y-6 text-slate-800 dark:text-slate-300 text-sm md:text-base text-justify'>
                <p><b>(1)</b> Během druhé světové války nacisté zabavovali zvony a roztavovali je pro potřeby válečného průmyslu. Nařízení, jímž zloději ve vojenských uniformách své počínání legitimizovali, bylo vydáno dne 26. 11. 1941. Následujícího roku z území protektorátu Čechy a Morava vojáci odvezli přes 90 % všech zdejších zvonů. Češi se tehdy museli rozloučit s 9 801 zvony.</p>
                <p>Vzpomínkou na smutné časy je nedávno odlitý zvon se symbolickým názvem, <b>jenž</b> své bratry proměněné ve zbraně připomíná jak jménem, tak svou hmotností 9 801 kg. Zvon #9801 byl z velké části financován veřejnou sbírkou, jejíž organizace se ujali členové spolku příznivců zvonařství. Jeho výroba byla pro zvonaře z rakouské firmy Grassmayr skutečnou výzvou.</p>
                <p><b>(2)</b> Sbírka byla zahájena 3. února 2022 (celkem se vybralo 12,5 milionu Kč), samotný zvon byl odlit již 10. června téhož roku. Pozoruhodnou reliéfní výzdobu, která mimo jiné vzdává čest zvonařům, jejichž práce byla za války zničena, vytvořili pražští mistři.</p>
                <p>A jak zvony vůbec vznikají? Nejprve se z vosku vytvoří tzv. falešný zvon... Samotné odlití zvonu trvá krátce (zvon #9801 byl prý odlit za pouhých šest minut), je však značně rizikové. Při odlévání má totiž roztavená zvonovina teplotu přes 1 000 °C.</p>
                <p>Po vychladnutí se forma rozbije a zvon je na světě. Zvon #9801 se v Praze poprvé rozezněl koncem srpna 2022. Toto výjimečné dílo slouží jako varování, že umění lze snadno přetavit ve smrticí nástroj.
                <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium'>(www.9801.cz; www.denikn.cz, upraveno)</p>
            </div>";
            
            string textPisek = @"<div class='columns-1 lg:columns-2 gap-8 space-y-6 text-slate-800 dark:text-slate-300 text-sm md:text-base text-justify'>
                <p>Pokud zavítáte do jižních Čech, nesmíte vynechat návštěvu Písku. V tomto malebném
                   městě se nachází nejstarší dochovaný kamený most na našem území (někdy zvaný
                   Jelení) a další významné pamětihodnosti. Součástí historického centra je také <u>písecká</u>
                   <u>sladovna</u>. Stojí na břehu řeky Otavy a vybudována byla v 19. století. Skoro 100 let zde
                   byla výrobna sladu pro pivovary, v současné době tento bývalý průmyslový objekt slouží
                   jako kulturní středisko.</p>
                <p>Rozlehlá čtyřpatrová budova nabízí rozličné výstavy, které <u>vám</u> pomocí kreativních
                   her sprostředkují spoustu zážitků. Jedna ze stálých expozic má název Mraveniště. Jde
                   o obří dřevěný labyrint, který je plný skrýší a přibližuje nelehký život v mravenčí kolonii.
                   Na výstavě pojmenované Království včel a bylin zase prozkoumáte včelý město. Na dalším
                   místě se ponoříte do dechberoucího světa animace, jinde objevíte kouzlo ilustrovaných
                   knih. Návštěvu tohoto kulturního střediska si zajisté náramě užijete.</p>
                <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs'><i>~Podtržené výrazy jsou zapsány správně.~</i></p>
                <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium'>(www.sladovna.cz, upraveno)</p>
                </div>";
            string textTanec = @"<div class='bg-slate-100 dark:bg-slate-900/50 p-5 rounded-2xl border border-slate-200 dark:border-white/5'>
                <h4 class='text-[10px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-4'>Tanec s hudbou</h4>
                <p class='mb-4 text-slate-800 dark:text-slate-300 text-sm md:text-base'>Zářivě bílou pláž omývají vlny tyrkysového Tichého oceánu a pod palmami tančí krásky s nádhernými květinovými věnci kolem krku. Jejich ladné pohyby ale nemají jen okouzlit turisty z plážových hotelů. Tanec hula je zejména výrazem úcty k havajské přírodě a kultuře.</p>
                <p class='text-slate-800 dark:text-slate-300 text-sm md:text-base'>Původně hula tančili jenom muži, a to při zpěvu „a cappella“ (tj. zpěv bez doprovodu hudebních nástrojů). Postupem času se do tance zapojily i ženy a přidaly se hudební nástroje. Dnes při hula hudebníci často hrají na ukulele nebo se tančí v rytmu bubnů. Pokud si chcete tuto starou havajskou tradici dosyta užít, zajeďte v květnu na ostrov Molokai. Zde se již od roku 1991 každoročně koná třídenní festival tance hula.</p>
            </div>";

            string textStopar = @"<div class='grid grid-cols-1 lg:grid-cols-2 gap-8 text-slate-800 dark:text-slate-300 text-sm md:text-base'>
                <div>
                    <p class='mb-4'>Arthur Dent se ve čtvrtek v osm ráno necítil nejlíp. Mátožně bloumal po ložnici, otevřel okno, uviděl, jak obrovský žlutý buldozer vjíždí na jeho zahradu, odkráčel do koupelny a začal se mýt. <b>Myslí</b> mu přitom bloudilo slovo buldozer a hledalo, s čím by se mohlo spojit. Matně se rozpomínal, že včera vypěnil. Cože to bylo? Ach ano, večer se přece v hospodě rozčiloval KVŮLI STAVBĚ dálničního obchvatu, o <b>níž</b> se zrovna ten den dozvěděl.</p>
                    <p class='mb-4'>O patnáct vteřin později už Arthur ležel v bahně před buldozerem.</p>
                    <p class='mb-4'>L. Prosser byl jenom člověk. Konkrétně řečeno, byl to asi čtyřicetiletý, dosti obtloustlý zaměstnanec obecní rady v poněkud ošuntělém oděvu. Teď právě stál nad Arthurem a snažil se ho zviklat: „No tak, pane Dente, tohle nevyhrajete. Nemůžete tady přece ležet NAVĚKY.“</p>
                    <p>Arthur dál <u>ležel v blátě</u> a šklebil se: „Vsaďte se!“</p>
                </div>
                <div>
                    <p class='mb-4'>„Obávám se, že se s tím obchvatem budete muset smířit,“ opáčil L. Prosser. „Měl jste právo v zákonné lhůtě vznést námitky nebo předložit protinávrh. Ty plány byly vyvěšené na plánovacím oddělení úřadu pro místní rozvoj tři čtvrtě roku.“</p>
                    <p class='mb-4'>„Šel jsem se tam na ty plány podívat hned, jak jsem zjistil, že mi chcete zbourat dům.“</p>
                    <p class='mb-4 text-rose-600 dark:text-rose-400 font-bold'>[ ***** ]</p>
                    <p class='mb-4'>„Ale jo. Byly ve sklepě vašeho úřadu na dně zamčené registračky. Tu jste vecpali na zrušený záchod a na dveře dali ceduli Pozor leopard!“ <br>L. Prosser raději změnil téma: „Dálniční obchvat se vám bude líbit.“</p>
                    <p class='mb-4'>„Hele, drž hubu,“ zavrčel Arthur, „<u>jdi do háje</u> i s tou svou pitomou dálnicí.“</p>
                    <p>L. Prosser zalapal po dechu, rychle se ale vzpamatoval: „Pane Dente, rád bych vám poskytl věcnou informaci. Víte, jakou škodu by utrpěl tenhle buldozer, kdybych ho pustil a on vás převálcoval?“<br>„Jakou?“<br>„Vůbec žádnou,“ řekl klidným hlasem L. Prosser a odmašíroval.</p>
                    <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium'>(D. Adams, Stopařův průvodce Galaxií, upraveno)</p>
                </div>
            </div>";

            string textGorila = @"<div class='columns-1 lg:columns-2 gap-8 space-y-4 text-slate-800 dark:text-slate-300 text-sm md:text-base'>
                <p><b>(1)</b> Američtí psychologové Christopher Chabris a Daniel Simons uskutečnili na konci 90. let experiment, známý jako test neviditelné gorily. Natočili půlminutové video, v němž si dva tříčlenné týmy (jeden v černých, druhý v bílých tričkách) hází dvěma míči. Mezi přihrávající si hráče zhruba ve 20. vteřině vstoupí člověk převlečený za gorilu, několikrát se uhodí do hrudi a zase odkráčí.</p>
                <p>Účastníci experimentu měli za úkol počítat přihrávky bílých triček. Následně se vědci ptali, <b>[ 1 ]</b> si někdo všiml něčeho zvláštního. Zjistili, že přes 40 % dotazovaných gorilu vůbec nezaregistrovalo. Nejde o to, že by na ni zapomněli. Oni ji skutečně neviděli: <b>[ 2 ]</b> se totiž naše pozornost soustředí na jednu konkrétní věc, náš mozek další vjemy <b>ignoruje</b>. Tomuto <b>fenoménu</b> se říká slepota z nepozornosti. Své závěry vědci popsali v knize Neviditelná gorila.</p>
                <p><b>(2)</b> Psycholog Trafton Drew podobným způsobem zkoušel schopnosti radiologů. Ti měli na rentgenových snímcích lidského těla hledat známky nemoci, přičemž na některé ze snímků byl přidán obrázek gorily. Odhalilo ji pouze 17 % testovaných. Je tedy evidentní, že mozek i oči nám někdy zalžou.</p>
                <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium'>(Vzhledem k povaze jedné z úloh není zdroj výchozího textu uveden.)</p>   
            </div>";

