        private List<CermatTask> GetMaturita2025Podzim()
        {
            string textDublin = @"<div class='bg-slate-100 dark:bg-slate-900/50 p-5 rounded-2xl border border-slate-200 dark:border-white/5'>
                <h4 class='text-[10px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-4'>TEXT 1</h4>
                <p class='text-slate-800 dark:text-slate-300 text-sm md:text-base text-justify mb-4'><b>(1)</b> Dublin zná leckdo jen z filmů, kde v šedých ulicích <b>NEUSTÁLE</b> mrholí. Tato irská metropole vás ale překvapí svou nádherou. Je totiž pestrá a nepochybně svérázná: muzikantů má téměř tolik co obyvatel, je tu na 700 hospod a každá je jiná. Ve všech se ovšem čepuje pivo značky Guinness, na něž jsou Dubliňané náležitě hrdí. <u>Chmel a slad ať Bůh zachová, pronášejí nad sklenicí lahodného moku.</u></p>
                <p class='text-slate-800 dark:text-slate-300 text-sm md:text-base text-justify'><b>(2)</b> K turistickým atrakcím města patří i Phoenix Park – svou rozlohou (v nejširším místě má přes 4 km) se řadí mezi největší evropské městské parky. Opomenout nelze ani zdejší katedrálu sv. Patrika, <u>v níž v 18. století působil místní rodák Jonathan Swift</u>. <u>Tento duchovní je proslulý především tím, že napsal imaginární cestopis Gulliverovy cesty.</u> Swiftem ovšem výčet slavných místních spisovatelů teprve začíná. Pokračovat můžeme třeba třemi laureáty Nobelovy ceny za literaturu: přímo z Dublinu <b>pochází</b> G. B. Shaw, <b>NEDALEKO</b> od tohoto města přišli na svět William B. Yeats a Samuel Beckett. Možná ještě slavnějším než tato trojice je i další z dublinských umělců, Oscar Wilde. Žádný literát ovšem není s Dublinem tak bytostně propojen jako <b>[ ***** ]</b>. Tento velikán světové moderny, známý metodou vyprávění zvanou proud vědomí, zasadil do tohoto města děj nejednoho svého díla. Například na více než 1000 stranách románu <b>[ ..... ]</b>, inspirovaného antickým mýtem, <b>popisuje</b> očima svého hrdiny Leopolda Blooma město tak detailně, že by starý Dublin mohl být na základě tohoto líčení postaven znovu. Mistrům pera je v Dublinu věnováno zvláštní muzeum (Muzeum irské literatury), kde je možné zhlédnout spoustu literární korespondence, k vidění jsou tu i jejich dochované osobní předměty. V tomto muzeu probíhají také dočasné výstavy či zajímavé besedy, svá autorská čtení tu mají mladí autoři. Jejich debuty najdeme i mezi tituly vystavenými ve výloze přilehlého knihkupectví. Spolu s dalšími kulturními akcemi jsou důkazem, že na poli literárního umění nežije Dublin jen ze své velkolepé minulosti.</p>
                <p class='text-slate-500 dark:text-slate-400 mt-4 text-xs font-medium'>(kol. autorů, Toulky Evropou: pozoruhodná místa starého kontinentu, upraveno)</p>

                <h4 class='text-[10px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-4 mt-6'>TEXT 2</h4>
                <p class='text-slate-800 dark:text-slate-300 text-sm md:text-base text-justify'>Tvarotvorná předpona <b>po-</b> je předpona, pomocí níž se u některých sloves tvoří tvary budoucího času (např. poletí je tvar slovesa letět). Předpona <b>po-</b> není tvarotvorná, když ji má sloveso ve všech svých tvarech (např. slovesa polykat či povolit tvarotvornou předponu <b>po-</b> nemají: sloveso lykat neexistuje, povolit a volit jsou různá slovesa s odlišným významem).</p>
            </div>";

            string textMloky = @"<div class='space-y-4 text-slate-800 dark:text-slate-300 text-sm md:text-base'>
                <p><i>Úkolem je seřadit jednotlivé části textu (A–E) tak, aby byla dodržena textová návaznost (K. Čapek, Válka s Mloky).</i></p>
            </div>";

            string textSlezske = @"<div class='bg-slate-100 dark:bg-slate-900/50 p-5 rounded-2xl border border-slate-200 dark:border-white/5'>
                <h4 class='text-[10px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-4'>TEXT 1</h4>
                <p class='whitespace-pre-line italic text-slate-800 dark:text-slate-300 leading-relaxed text-sm md:text-base mb-4'>Žil jsem jak stepní kůň svobody
                ciz lidem v životě prostém,
                dávno jsem zahodil do vody
                skřipky s tím jediným mostem;
                nevím, jak strunu tu vložili
                v srdce mi bohové přísní,
                hořem půl, vodkou půl opilý
                vázal jsem věnec svých písní;
                z bodláčí, z pokřivy nehezké,
                z trní a ze slz byl uvit,
                byl jsem – sto pěrunů! – ze Slezské,
